INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(17, 'เขื่อนกันดินไทรม้า 19 EP.1', 'สร้างเขื่อนกันดินซอยไทรม้า 19 ระยะความยาวทั้งหมด 49.5 เมตร', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    บันทึกหน้างาน EP.1: เริ่มต้นโปรเจกต์สร้างเขื่อนกำแพงกันดิน 49.5 เมตร ซอยไทรม้า 19 พร้อมเจาะลึกอุปสรรคใต้ผิวดิน\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-flag-checkered\"></i> อัปเดตการทำงานวันแรก (Day 1) | <i class=\"fa fa-map-marker\"></i> พิกัด: ซอยไทรม้า 19 จังหวัดนนทบุรี\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #f8f9fa; padding: 25px; border-left: 5px solid #0056b3; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    จุดเริ่มต้นของความมั่นคง เริ่มต้นที่รากฐานที่ดี! วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ขอพาทุกท่านลงพื้นที่จริง ประเดิมวันแรก (Day 1) ของโปรเจกต์ก่อสร้าง <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\" style=\"color: #0056b3; font-weight: bold;\">เขื่อนและกำแพงกันดิน</a> โครงการใหญ่ ณ ซอยไทรม้า 19 \n                    <br><br>\n                    ใน EP.1 นี้ เราจะพาไปดูธรรมเนียมปฏิบัติก่อนเริ่มงานก่อสร้าง เจาะลึกสเปกโครงสร้างระดับวิศวกรรมที่ใช้รับมือกับแรงดันดิน และพาวิเคราะห์ <strong>\"2 อุปสรรคสุดหิน\"</strong> ที่ซ่อนอยู่ใต้ผิวดิน ซึ่งทีมงานของเราต้องเตรียมรับมืออย่างเร่งด่วนครับ\n                </p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. ฤกษ์งามยามดี: การบวงสรวงเจ้าที่ เพื่อขวัญกำลังใจและความปลอดภัยสูงสุด (Zero Accident)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ในวงการรับเหมาก่อสร้างของไทย ไม่ว่าเทคโนโลยีและเครื่องจักรจะก้าวล้ำไปไกลแค่ไหน สิ่งหนึ่งที่ทีมงานมืออาชีพไม่เคยละทิ้งคือ <strong>\"ความเคารพต่อสถานที่\"</strong> \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ก่อนที่เครื่องจักรหนักจะสตาร์ทเครื่องยนต์ ทีมงานธีรพงษ์เซอร์วิสได้จัดเตรียมเครื่องเซ่นไหว้ เพื่อทำพิธีบอกกล่าวและขอขมาเจ้าที่เจ้าทาง สิ่งศักดิ์สิทธิ์ที่ปกปักรักษาพื้นที่บริเวณซอยไทรม้า 19 พิธีกรรมนี้นอกจากจะเป็นสิริมงคลตามความเชื่อแล้ว ในมิติของการทำงาน ยังเป็นการ <strong>\"สร้างขวัญและกำลังใจ\"</strong> ให้กับทีมช่างและพนักงานขับเครื่องจักรทุกคน ให้มีความรอบคอบ มีสติ และตั้งเป้าหมายการทำงานภายใต้มาตรฐานความปลอดภัยสูงสุด (Zero Accident) ตลอดทั้งโครงการครับ\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/28165.webp\" alt=\"พิธีไหว้เจ้าที่ก่อนเริ่มงานก่อสร้างกำแพงกันดิน ซอยไทรม้า 19\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 400px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: พิธีไหว้บอกกล่าวสิ่งศักดิ์สิทธิ์ เพื่อความราบรื่นและปลอดภัยก่อนเริ่มลุยหน้างาน</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. สแกนสเปกโครงสร้าง: เขื่อนกันดินยาว 49.5 เมตร พร้อมระบบสเตย์เต็มรูปแบบ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                สำหรับรายละเอียดของโปรเจกต์ไทรม้า 19 นี้ ถือเป็นงานสเกลระดับกลางค่อนไปทางใหญ่ โดยมีโจทย์คือการสร้างแนวป้องกันดินสไลด์และปรับระดับพื้นที่ให้สวยงาม มั่นคง โดยมีรายละเอียดทางวิศวกรรมที่น่าสนใจดังนี้:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-6\">\n                    <ul class=\"list-group\" style=\"font-size: 16px;\">\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-arrows-h\"></i> ความยาวรวม 49.5 เมตร</h4>\n                            <p style=\"margin-bottom: 0;\">เป็นระยะทางที่ต้องใช้การวางแผนแนวระดับ (Alignment) ที่แม่นยำ เพื่อไม่ให้กำแพงคดเคี้ยว หรือเกิดการทรุดตัวไม่เท่ากัน (Differential Settlement) ตลอดแนว</p>\n                        </li>\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-anchor\"></i> เสาเข็มไมโครไพล์ I22 (จำนวน 110 ต้น)</h4>\n                            <p style=\"margin-bottom: 0;\">เราเลือกใช้ <strong>เสาเข็มหน้าตัดตัวไอ ขนาด 22x22 ซม. (Micropile I22)</strong> ความยาว 10 เมตร ซึ่งมีข้อดีคือรูปทรงตัวไอจะช่วยเพิ่มพื้นที่ผิวสัมผัส (Surface Area) สร้างค่าความฝืดกับชั้นดินได้มหาศาล รองรับน้ำหนักได้ดีกว่าเข็มหน้าตัดทั่วไป</p>\n                        </li>\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-danger\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-link\"></i> ระบบสเตย์ดึงรั้ง \"ทุกต้น\"</h4>\n                            <p style=\"margin-bottom: 0;\">เพื่อความแข็งแกร่งระดับสูงสุด เราไม่ได้ทำสเตย์แบบเว้นระยะ แต่เราออกแบบให้มีการตอกเสาเข็มสเตย์และหล่อคานดึงรั้ง <strong>\"ประกบเสาเข็มหลักทุกต้น\"</strong> เพื่อรับแรงอัดจากมวลดินด้านข้างได้อย่างสมบูรณ์แบบ ไร้กังวลเรื่องกำแพงแบะล้ม 100%</p>\n                        </li>\n                    </ul>\n                </div>\n                <div class=\"col-md-6 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/saima-19-bobby.webp\" alt=\"สภาพหน้างานโครงการสร้างเขื่อนกันดิน ซอยไทรม้า 19\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1); margin-bottom: 15px;\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/28165.webp\" alt=\"เตรียมความพร้อมเครื่องจักรและหน้างาน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2-3: สภาพหน้างานวันแรก ที่รอการปรับพื้นที่และลงเสาเข็มทั้ง 110 ต้น</em></p>\n                </div>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ความท้าทายหน้างาน: 2 อุปสรรคใหญ่ที่ซ่อนอยู่ใต้ผิวดิน!\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากทำพิธีเปิดไซต์งานและเตรียมนำเครื่องจักรเข้าพื้นที่ ทีมสำรวจของเราได้ทำการเช็กสภาพพื้นผิวและแนวตอกเข็มอย่างละเอียด ซึ่งก็พบกับ <strong>\"อุปสรรคสุดหิน 2 ประการ\"</strong> ที่ทำให้แผนการทำงานปกติไม่สามารถเดินหน้าได้ทันที:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-warning\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold; color: #8a6d3b;\"><i class=\"fa fa-exclamation-triangle\"></i> อุปสรรคที่ 1: สภาพดินเดิมเป็น \"ดินเลน\"</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; line-height: 1.6;\">\n                            พื้นที่บริเวณนี้เคยมีการนำ <a href=\"https://www.theeraphong.com/รับถมดิน\" target=\"_blank\" style=\"color: #c9302c; font-weight: bold; text-decoration: underline;\">ดินถม</a> มาลงไว้ก่อนหน้านี้ แต่วัสดุที่ใช้ถมกลับมีลักษณะเป็น <strong>\"ดินเลน (Soft Mud)\"</strong> ที่อุ้มน้ำและไม่มีความหนาแน่น <br><br>\n                            <strong>ผลกระทบ:</strong> ดินประเภทนี้ไม่มีกำลังรับน้ำหนัก (Bearing Capacity ต่ำมาก) หากนำรถแบคโฮหรือเครื่องจักรกดเสาเข็มเข้าไปวิ่งโดยตรง รถมีโอกาสจมโคลนลึก หรือพลิกคว่ำได้ ซึ่งอันตรายต่อทั้งทีมงานและเครื่องจักรอย่างยิ่ง\n                        </div>\n                    </div>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-warning\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold; color: #8a6d3b;\"><i class=\"fa fa-exclamation-triangle\"></i> อุปสรรคที่ 2: \"หินขนาดใหญ่\" ใต้แนวสันเขื่อนเดิม</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; line-height: 1.6;\">\n                            เมื่อทำการขุดสำรวจตามแนวพิกัดที่จะต้องกดเสาเข็ม เราพบว่าภายใต้ชั้นดินนั้น มี <strong>แนวหินทิ้งขนาดใหญ่</strong> ที่หลงเหลือมาจากการทำสันเขื่อนหรือการถมในอดีต ซ่อนตัวอยู่เป็นจำนวนมาก <br><br>\n                            <strong>ผลกระทบ:</strong> การกดเสาเข็มไมโครไพล์ I22 หากปลายเข็มปะทะเข้ากับก้อนหินแข็ง จะทำให้เกิดปัญหา \"เสาเข็มหนีศูนย์ (เยื้องศูนย์)\" ทำให้แนวกำแพงบิดเบี้ยว หรือเลวร้ายที่สุดคือเสาเข็มแตกหักใต้ดินจนสูญเสียความแข็งแรง\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <div class=\"alert alert-info\" style=\"margin-top: 40px; border-left: 5px solid #31708f; padding: 25px;\">\n                <h3 style=\"color: #31708f; margin-top: 0;\"><i class=\"fa fa-cogs\"></i> บทสรุป EP.1 และความน่าติดตามในตอนต่อไป</h3>\n                <p style=\"font-size: 16px; line-height: 1.8; margin-bottom: 0;\">\n                    ปัญหา <strong>\"ดินเลนอ่อนยวบ\"</strong> และ <strong>\"กองหินใต้น้ำ\"</strong> คือฝันร้ายที่สามารถทำให้ผู้รับเหมาหลายรายต้องทิ้งงาน แต่สำหรับทีมงานมืออาชีพอย่าง <strong>ธีรพงษ์เซอร์วิส</strong> อุปสรรคเหล่านี้คือความท้าทายที่เราเตรียมแผนสำรองไว้เสมอ! \n                    <br><br>\n                    <strong>วิธีการแก้ไขปัญหา (Problem Solving)</strong> ของทีมวิศวกรและช่างควบคุมเครื่องจักรของเราจะเป็นอย่างไร? เราจะฝ่าด่านดินเลนและจัดการกับหินใต้ดินเพื่อกดเสาเข็มทั้ง 110 ต้นให้สำเร็จได้อย่างไร? <br>\n                    👉 <strong>รอติดตามคำตอบและเทคนิคเชิงช่างสุดเจ๋งได้ใน <a href=\"#\" style=\"color: #c9302c; font-weight: bold;\">อัปเดตงานกำแพงกันดิน ซอยไทรม้า 19 (EP.2)</a> เร็วๆ นี้ครับ!</strong>\n                </p>\n            </div>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> ถาม-ตอบ (FAQ) ความรู้ก่อนเริ่มสร้างกำแพงกันดิน</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: ทำไมต้องใช้ เสาเข็มไมโครไพล์ (Micropile) ในการทำกำแพงกันดิน?</h4>\n                <p style=\"margin-bottom: 20px;\">A: ไมโครไพล์ถูกออกแบบมาเพื่อหน้างานที่มีพื้นที่จำกัด หรือเข้าถึงยากครับ นอกจากนี้ การใช้ระบบ \"กดเข็ม (Hydraulic Static Pile)\" แทนการตอกด้วยตุ้มน้ำหนัก จะช่วยลดแรงสั่นสะเทือน (Low Vibration) ไม่ทำให้บ้านเรือนข้างเคียงเกิดรอยร้าว ซึ่งเหมาะมากสำหรับหน้างานในซอยชุมชนอย่างซอยไทรม้าครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: หากดินถมเดิมเป็นดินเลน สามารถเทคอนกรีตทับเลยได้ไหม?</h4>\n                <p>A: <strong>ไม่ได้เด็ดขาดครับ</strong> ดินเลนมีการทรุดตัวสูงมาก หากเทคอนกรีตทับโดยไม่ปรับปรุงคุณภาพดิน หรือไม่มีเสาเข็มรองรับ ในเวลาไม่นานโครงสร้างคอนกรีตจะเกิดการแตกร้าวและทรุดตามชั้นดินอย่างแน่นอน ต้องมีการปูแผ่นกระจายน้ำหนัก หรือขุดลอกดินเลนออกก่อนเริ่มงานครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #0056b3; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">มองหาทีมงานรับเหมาที่ \"ไม่หนีปัญหา\" ใช่หรือไม่?</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    งานฐานรากและกำแพงกันดิน มักมาพร้อมกับอุปสรรคที่คาดไม่ถึงเสมอ <br>\n                    เลือกทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> ที่มีประสบการณ์ตรง มีเครื่องจักรพร้อมลุย และมีความรับผิดชอบ ไม่ทิ้งงาน!\n                </p>\n                \n                <div class=\"row\">\n                    <div class=\"col-sm-6 text-right\">\n                        <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-primary btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                            <i class=\"fa fa-shield\"></i> บริการรับทำกำแพงกันดิน\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6 text-left\">\n                        <a href=\"https://www.theeraphong.com/images/pile\" class=\"btn btn-info btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px; background-color: #17a2b8; border-color: #17a2b8; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                            <i class=\"fa fa-cogs\"></i> บริการกดเสาเข็มไมโครไพล์\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1710671722259177.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP1', '2021-09-12 05:14:45', '2021-09-12 09:10:06'),
(18, 'เขื่อนกันดินไทรม้า 19 EP.2', 'อัพเดทงานสร้างเขื่อนกันดิน ซอยไทรม้า 19', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    เจาะลึกงานฐานรากเขื่อนกันดิน: ลุยเคลียร์หินใต้น้ำ เตรียมกดเสาเข็มไอ (Micropile) 110 ต้น พร้อมเทคนิคหล่อแผ่นเสียบหน้างาน\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตข้อมูลหน้างานประจำวันที่ 14-09-2021 | <i class=\"fa fa-wrench\"></i> หมวดหมู่: อัปเดตผลงาน, เทคนิคงานฐานราก\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #f8fcf8; padding: 25px; border-left: 5px solid #5cb85c; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    การสร้าง <strong>\"เขื่อนกำแพงกันดิน\"</strong> ในพื้นที่ที่อยู่ติดแหล่งน้ำหรือมีระดับดินต่างกันมาก จำเป็นต้องอาศัยรากฐานที่แข็งแกร่งที่สุดเพื่อต้านทานแรงดันมหาศาล วันนี้ทีมงาน <a href=\"https://www.theeraphong.com/\" target=\"_blank\" style=\"color: #2e6da4; font-weight: bold;\">ธีรพงษ์เซอร์วิส (Theeraphong Service)</a> จะพาทุกท่านมาเกาะติดสถานการณ์หน้างานจริง กับภารกิจการเตรียมความพร้อมในขั้นตอนที่สำคัญที่สุด นั่นคือ <strong>\"งานกดเสาเข็มไมโครไพล์ (Micropile)\"</strong> และ <strong>\"การเตรียมโครงเหล็กหล่อแผ่นเสียบ\"</strong> มาดูกันว่าทีมงานมืออาชีพมีวิธีรับมือกับอุปสรรคใต้น้ำ และบริหารเวลาอย่างไรให้งานออกมาได้มาตรฐานและตรงตามกำหนดเวลาครับ!\n                </p>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. ภารกิจลำเลียง: ขนย้ายเสาเข็มไอ (I-Shape Micropile) ความยาว 10 เมตร เข้าสู่พื้นที่\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เริ่มต้นวันทำงานด้วยการวางแผนด้านโลจิสติกส์ (Logistics) ทางทีมงานได้เริ่มดำเนินการขนย้าย <strong>เสาเข็มหน้าตัดรูปตัวไอ (I-Shape Micropile)</strong> เข้าสู่พื้นที่หน้างานอย่างเป็นระบบ สำหรับโปรเจกต์นี้ เราเลือกใช้เสาเข็มที่มีความยาวถึง <strong>10 เมตร</strong> จำนวนรวมทั้งสิ้น <strong>110 ต้น</strong> \n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-6 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-2.webp\" alt=\"การลำเลียงและเตรียมความพร้อม เสาเข็มไอ (Micropile) ความยาว 10 เมตร\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1); margin-bottom: 15px;\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>ภาพที่ 1: กองเสาเข็มไอ (I-Shape Micropile) ที่ถูกจัดเรียงอย่างเป็นระเบียบ เตรียมพร้อมสำหรับการกดลงดิน</em></p>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-info\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold;\"><i class=\"fa fa-info-circle\"></i> ทำไมถึงต้องเป็นเสาเข็มตัวไอ (I-Shape)?</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; line-height: 1.6;\">\n                            ในงานกำแพงกันดิน เสาเข็มไม่ได้ทำหน้าที่แค่รับน้ำหนักในแนวดิ่ง (Vertical Load) แต่ต้องรับ <strong>แรงดัด (Bending Moment)</strong> และแรงดันดินด้านข้าง (Lateral Earth Pressure) ด้วย <br><br>\n                            เสาเข็มหน้าตัดตัวไอ มีคุณสมบัติเด่นคือมีพื้นที่ผิวสัมผัส (Surface Area) กับดินที่มากกว่าเสาเข็มสี่เหลี่ยมตัน ทำให้เกิด <strong>\"ค่าความฝืด (Skin Friction)\"</strong> ที่สูงมาก ช่วยยึดเกาะกับชั้นดินได้อย่างเหนียวแน่น ป้องกันการเคลื่อนตัวของกำแพงได้อย่างมีประสิทธิภาพสูงสุดครับ\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. เผชิญหน้าอุปสรรค: ภารกิจเคลียร์ \"หินใต้น้ำ\" ก่อนเริ่มกดเข็ม\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ในการทำงานจริงมักไม่ได้โรยด้วยกลีบกุหลาบเสมอไป หลังจากทีมสำรวจได้เช็กระดับและแนวแกนที่จะทำการกดเสาเข็ม เราได้พบกับปัญหาสำคัญคือ <strong>\"แนวหินก้อนใหญ่ที่ทับถมอยู่ด้านล่างใต้น้ำ\"</strong> ซึ่งคาดว่าเป็นเศษวัสดุจากการทำสันเขื่อนหรือการถมที่ในอดีต\n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                <strong>ความเสี่ยงทางวิศวกรรม:</strong> หากเราดึงดันที่จะกดเสาเข็มลงไปโดยไม่นำหินเหล่านี้ออกก่อน ปลายเสาเข็มจะไปปะทะกับก้อนหิน ทำให้เกิดปัญหา <strong>เสาเข็มหนีศูนย์ (Pile Deviation)</strong> หรือเลวร้ายที่สุดคือเสาเข็มหักร้าวใต้ผิวดิน ซึ่งจะทำให้ฐานรากจุดนั้นสูญเสียความสามารถในการรับน้ำหนักไปในทันที\n            </p>\n\n            <div class=\"alert alert-warning\" style=\"margin-top: 20px; border-left: 5px solid #f0ad4e;\">\n                <h4 style=\"color: #c12e2a; margin-top: 0; font-weight: bold;\"><i class=\"fa fa-exclamation-triangle\"></i> วิธีการแก้ปัญหาของทีมงานธีรพงษ์เซอร์วิส</h4>\n                <p style=\"font-size: 16px; margin-bottom: 0; line-height: 1.6;\">\n                    เพื่อความสมบูรณ์แบบของโครงสร้าง เราได้สั่งหยุดการกดเข็มชั่วคราว และปรับแผนโดยนำ <strong>รถแบคโฮ (แมคโคร)</strong> เข้ามาทำการงมและตักหินใต้น้ำในแนวพิกัดเสาเข็มออกให้หมด (Clearing) เพื่อเปิดชั้นดินให้โล่งที่สุด แม้ขั้นตอนนี้จะทำให้เสียเวลาเพิ่มขึ้น แต่เพื่อแลกกับความปลอดภัยและความแข็งแรงร้อยเปอร์เซ็นต์ของกำแพงกันดิน ถือเป็นขั้นตอนที่ \"ข้ามไม่ได้เด็ดขาด\" ครับ\n                </p>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. แผนการดำเนินงาน: กดเสาเข็ม 110 ต้น ภายใน 4-5 วัน\n            </h2>\n            \n            <p style=\"line-height: 1.8; font-size: 16px; margin-top: 20px;\">\n                หลังจากเคลียร์สิ่งกีดขวางใต้น้ำเสร็จสิ้น ทีมงานจะเข้าสู่กระบวนการนำรถแบคโฮ (แมคโคร) มากดเสาเข็มไอ (Hydraulic Static Pile Driving) การใช้น้ำหนักและระบบไฮดรอลิกของรถแบคโฮในการกดเข็ม มีข้อดีอย่างมหาศาลคือ <strong>\"ก่อให้เกิดแรงสั่นสะเทือนต่ำ (Low Vibration)\"</strong> และไม่มีเสียงดังรบกวนเหมือนการใช้ปั้นจั่นตอก จึงปลอดภัยต่อโครงสร้างบ้านเรือนข้างเคียง\n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ด้วยความชำนาญของทีมช่างและคนขับเครื่องจักร เราได้วางไทม์ไลน์ประเมินการทำงานไว้ว่า การกดเสาเข็มทั้งหมด <strong>110 ต้น</strong> จะใช้เวลาดำเนินการเพียง <strong>4-5 วัน โดยประมาณ</strong> (เฉลี่ยกดได้ 20-25 ต้นต่อวัน) ซึ่งถือเป็นอัตราความเร็วที่ยอดเยี่ยม ช่วยให้เจ้าของโครงการประหยัดเวลาและลดความกังวลเรื่องผลกระทบต่อชุมชนรอบข้างได้อย่างดีครับ\n            </p>\n\n            <h2 style=\"color: #2e6da4; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. การบริหารเวลาแบบมืออาชีพ: เตรียมพื้นที่ \"หล่อแผ่นเสียบ\" แบบคู่ขนาน\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เสน่ห์ของการบริหารโครงการก่อสร้าง (Construction Management) คือการไม่ปล่อยให้เวลาสูญเปล่า ในขณะที่ทีมเครื่องจักรกำลังเตรียมการเรื่องการกดเสาเข็ม อีกด้านหนึ่งของพื้นที่หน้างาน <strong>\"ทีมช่างโครงสร้าง\"</strong> ก็ได้ตระเตรียมพื้นที่และอุปกรณ์สำหรับ <strong>การหล่อแผ่นเสียบกำแพงกันดิน (Precast Concrete Panels)</strong> ควบคู่กันไปทันทีครับ\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-6 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-3.webp\" alt=\"การเตรียมพิมพ์หล่อแผ่นเสียบ และโครงเหล็กมาตรฐาน สำหรับงานกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1); margin-bottom: 15px;\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>ภาพที่ 2: พิมพ์หล่อและโครงเหล็กคุณภาพดี ที่เตรียมไว้สำหรับการเทปูนหล่อแผ่นเสียบหน้างาน</em></p>\n                </div>\n                <div class=\"col-md-6\">\n                    <h4 style=\"font-weight: bold; color: #333; margin-top: 0;\">มาตรฐานการหล่อแผ่นเสียบของธีรพงษ์เซอร์วิส</h4>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        หลายคนอาจสงสัยว่าทำไมเราถึงเลือกหล่อแผ่นเสียบที่หน้างาน (On-site Casting) แทนการซื้อแผ่นสำเร็จรูป? เหตุผลคือ:\n                    </p>\n                    <ul style=\"line-height: 1.8; font-size: 16px;\">\n                        <li><strong>การควบคุมคุณภาพเหล็กเสริม:</strong> เราสามารถใช้โครงเหล็กที่มีคุณภาพดี ผูกเหล็กได้ความถี่และระยะหุ้มคอนกรีต (Covering) ตามมาตรฐานวิศวกรรมเป๊ะๆ</li>\n                        <li><strong>ขนาดที่พอดี (Custom Fit):</strong> แผ่นเสียบที่หล่อจากพิมพ์มาตรฐานหน้างาน จะมีความหนาและขนาดที่สอดรับกับร่องของเสาเข็มไอได้สนิทพอดี ป้องกันดินรั่วไหล</li>\n                        <li><strong>จังหวะเวลาที่สมบูรณ์แบบ:</strong> ช่วงเวลาที่เราหล่อแผ่นเสียบทิ้งไว้ จะสอดคล้องกับระยะเวลา 4-5 วันที่ใช้กดเสาเข็มพอดี เมื่อกดเข็มเสร็จ คอนกรีตของแผ่นเสียบก็จะ <strong>เซ็ตตัวและได้ค่าความแข็งแรง (Compressive Strength)</strong> พร้อมนำไปเสียบประกอบได้ทันทีอย่างไร้รอยต่อครับ!</li>\n                    </ul>\n                </div>\n            </div>\n            \n\n            <div style=\"background-color: #f4f8fa; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #bce8f1;\">\n                <h3 style=\"color: #31708f; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> คำถามที่พบบ่อย (FAQ) งานกดเสาเข็มกำแพงกันดิน</h3>\n                <hr style=\"border-color: #9acfea;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: การกดเสาเข็มด้วยรถแมคโคร แข็งแรงสู้การตอกด้วยปั้นจั่นได้หรือไม่?</h4>\n                <p style=\"margin-bottom: 20px;\">A: แข็งแรงเท่าเทียมกันครับ หากกดจนถึงชั้นดินดานหรือชั้นดินที่ออกแบบไว้ (Pile Blow Count / Refusal) ข้อดีของการใช้แมคโครกดคือ ช่วยลดแรงกระแทกที่อาจทำให้หัวเข็มแตก และไม่สร้างแรงสั่นสะเทือนทำลายโครงสร้างบ้านเรือนที่อยู่ใกล้เคียงครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: แผ่นเสียบกำแพงกันดิน มีอายุการใช้งานนานเท่าไหร่?</h4>\n                <p>A: หากมีการผูกเหล็กเสริมอย่างถูกต้อง และเทคอนกรีตที่มีกำลังอัด (Strength) หนาแน่นเพียงพอ แผ่นเสียบเหล่านี้จะมีอายุการใช้งานทนทานยาวนานหลายสิบปีโดยไม่เปื่อยยุ่ยหรือทะลุครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #5cb85c; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">มาตรฐานงานฐานราก ที่คุณวางใจได้ 100%</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    ไม่ว่าหน้างานจะมีอุปสรรคใต้น้ำ หรือต้องใช้เทคนิคการทำงานที่ซับซ้อน <br>\n                    ทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> มีทั้งเครื่องจักรหนักและทีมช่างประสบการณ์สูง พร้อมลุยทุกสถานการณ์\n                </p>\n                \n                <div class=\"row\">\n                    <div class=\"col-sm-6 text-right\">\n                        <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-success btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                            <i class=\"fa fa-shield\"></i> ดูบริการรับทำกำแพงกันดิน\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6 text-left\">\n                        <a href=\"https://www.theeraphong.com/images/pile\" class=\"btn btn-primary btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                            <i class=\"fa fa-cogs\"></i> ดูผลงานกดเสาเข็มไมโครไพล์\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1710950087706025.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP2', '2021-09-15 06:59:15', '2021-09-15 06:59:15'),
(19, 'เขื่อนกันดินไทรม้า 19 EP.3', 'แก้ไขปัญหาหินใต้น้ำ งานสร้างเขื่อนกันดิน ซอยไทรม้า 19', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    เจาะลึกการแก้ปัญหาหน้างาน: ลุยเคลียร์หินใต้น้ำ และกดเสาเข็มไมโครไพล์ (Micropile) งานกำแพงกันดิน\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-wrench\"></i> อัปเดตความคืบหน้าหน้างาน | <i class=\"fa fa-map-marker\"></i> การแก้ปัญหาโครงสร้างและงานฐานราก\n                </p>\n            </div>\n\n            <p class=\"lead\" style=\"line-height: 1.8;\">\n                ในการรับเหมาก่อสร้าง <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\">กำแพงกันดิน (Retaining Wall)</a> โดยเฉพาะในพื้นที่ริมน้ำหรือแนวเขื่อนเดิม สิ่งที่ทีมงานมักจะต้องเตรียมรับมือเสมอคือ \"อุปสรรคใต้ผิวดิน\" วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> ได้เริ่มนำเครื่องจักรหนักเข้าเคลียร์พื้นที่และเตรียมกดเสาเข็ม แต่ก็ต้องพบกับโจทย์ใหญ่ที่ซ่อนอยู่ใต้น้ำ มาดูกันครับว่าทีมงานของเรามีวิธีรับมือและบริหารจัดการเวลาอย่างไรให้งานยังคงเดินหน้าต่อไปได้ตามแผน!\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. อุปสรรคหลัก: แนวหินทิ้งจากสันเขื่อนเดิมใต้น้ำ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากทีมงานเริ่มเดินเครื่องกดเสาเข็มด้วยรถแบคโฮ (แมคโคร) เราได้พบกับปัญหาหลักคือ <strong>\"แนวหินก้อนใหญ่ที่จมอยู่ใต้น้ำ\"</strong> ซึ่งเป็นหินที่ถูกทิ้งไว้จากโครงสร้างสันเขื่อนเดิมในอดีต ในทางวิศวกรรม หากเราฝืนกดเสาเข็มลงไปปะทะกับแนวหินเหล่านี้โดยตรง อาจส่งผลเสียร้ายแรงได้ เช่น เสาเข็มหนีศูนย์ (เยื้องศูนย์) เสาเข็มหัก หรือกดไม่ลงถึงระดับความลึกที่กำหนด\n            </p>\n\n            <div class=\"alert alert-info\" style=\"margin-top: 20px; border-left: 5px solid #31708f;\">\n                <h4 style=\"color: #31708f; margin-top: 0;\"><i class=\"fa fa-cogs\"></i> วิธีการแก้ปัญหาของทีมงาน</h4>\n                <p style=\"margin-bottom: 0; line-height: 1.6;\">\n                    เราสั่งหยุดการกดเข็มชั่วคราว และปรับแผนโดยนำรถแบคโฮ (แมคโคร) ติดตั้งหัวขุด ลงไปทำการ <strong>\"ตักและเกลี่ยแนวหินที่อยู่ใต้น้ำ\"</strong> ออกให้พ้นจากแนวแกนเสาเข็ม (Pile Line) ก่อน เพื่อเปิดทางให้ชั้นดินโล่งที่สุด แม้ขั้นตอนนี้จะทำให้เสียเวลาเพิ่มขึ้นเล็กน้อย แต่เพื่อความสมบูรณ์ร้อยเปอร์เซ็นต์ของฐานราก ถือเป็นสิ่งที่ข้ามไม่ได้เด็ดขาดครับ\n                </p>\n            </div>\n\n            <div class=\"row\" style=\"margin: 30px 0;\">\n                <div class=\"col-md-6 text-center\" style=\"margin-bottom: 20px;\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-7.webp\" alt=\"แนวหินทิ้งจากเขื่อนเดิมที่จมอยู่ใต้น้ำ อุปสรรคงานกดเสาเข็ม\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>ภาพแนวหินใต้น้ำที่เป็นอุปสรรคต่อการกดเสาเข็ม</em></p>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"embed-responsive embed-responsive-16by9\" style=\"border-radius: 8px; overflow: hidden; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                        <iframe class=\"embed-responsive-item\" src=\"https://www.youtube.com/embed/wSa5U9nbfDI\" allowfullscreen title=\"วิดีโอแมคโครขุดหินที่อยู่ใต้น้ำ งานกำแพงกันดิน\"></iframe>\n                    </div>\n                    <p class=\"text-muted text-center\" style=\"margin-top: 10px; font-size: 14px;\"><em>วิดีโอ: ปฏิบัติการใช้รถแมคโครเคลียร์แนวหินใต้น้ำ</em></p>\n                </div>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. เดินหน้าต่อ: ลุยกดเสาเข็ม Micropile ด้วยรถแบคโฮ Kobelco 135\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากเคลียร์สิ่งกีดขวางใต้น้ำเสร็จสิ้น ทีมงานที่มีความเชี่ยวชาญเฉพาะด้านของเราก็เดินหน้าเข้าสู่กระบวนการ <a href=\"https://www.theeraphong.com/images/pile\" target=\"_blank\">กดเสาเข็มไมโครไพล์ (Micropile)</a> อย่างเต็มกำลัง โดยใช้กำลังอัดจากรถ <strong>Kobelco SK135</strong> ซึ่งมีน้ำหนักกดที่เหมาะสม ทำให้การทำงานรวดเร็วและแม่นยำ \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ถึงแม้อุปสรรคในช่วงเช้าจะทำให้เวลาล่าช้าไปบ้าง แต่ด้วยประสบการณ์หน้างานและการวางแผนรับความเสี่ยง (Risk Management) ที่เผื่อเวลาไว้แล้ว ทำให้ภาพรวมของงานฐานรากยังคงเป็นไปตามเป้าหมายที่คาดคิดไว้ครับ\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/180921-3.jpg\" alt=\"รถแบคโฮ Kobelco 135 กำลังกดเสาเข็มไมโครไพล์ (Micropile)\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>ภาพการกดเสาเข็ม Micropile อย่างต่อเนื่องและแม่นยำด้วยแบคโฮ Kobelco 135</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. บริหารเวลาอย่างชาญฉลาด: งานหล่อแผ่นเสียบกำแพงกันดิน\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                จุดเด่นของการทำงานแบบมืออาชีพ คือการไม่ปล่อยให้เวลาสูญเปล่า ในขณะที่ทีมเครื่องจักรกำลังลุยกดเสาเข็มอยู่นั้น อีกฝั่งหนึ่งของหน้างาน <strong>\"ทีมช่างโครงสร้าง\"</strong> ก็ได้ดำเนินการเทปูนหล่อ <strong>แผ่นเสียบกำแพงกันดินคอนกรีตเสริมเหล็ก</strong> ควบคู่กันไปเป็นที่เรียบร้อยแล้วครับ\n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                การวางแผนงานคู่ขนานแบบนี้ (Parallel Workflow) ทำให้ <strong>ระยะเวลาที่ใช้ในการกดเสาเข็ม สอดคล้องพอดีกับระยะเวลาที่แผ่นปูนเซ็ตตัว (Curing Time)</strong> จนได้ค่าความแข็งแรง (Compressive Strength) ตามมาตรฐานวิศวกรรม เมื่อกระบวนการกดเสาเข็มเสร็จสิ้น แผ่นเสียบทั้งหมดก็จะแข็งแกร่งพร้อมสำหรับการนำไปเสียบประกอบลงในร่องแนวเสาเข็มได้ทันที ไร้รอยต่อของตารางงานครับ!\n            </p>\n\n            <div class=\"row\" style=\"margin: 30px 0;\">\n                <div class=\"col-sm-6 text-center\" style=\"margin-bottom: 20px;\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-6.webp\" alt=\"ช่างกำลังเทปูนหล่อแผ่นเสียบกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-height: 500px; object-fit: cover; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>เตรียมพร้อมเทคอนกรีตลงบล็อกแผ่นเสียบ</em></p>\n                </div>\n                <div class=\"col-sm-6 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-10.webp\" alt=\"งานหล่อแผ่นเสียบกำแพงกันดินคู่ขนานกับงานกดเข็ม\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-height: 500px; object-fit: cover; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>แผ่นเสียบที่เทเสร็จเรียบร้อย รอเวลาเซ็ตตัว</em></p>\n                </div>\n            </div>\n\n            <hr style=\"margin: 40px 0;\">\n\n            <div class=\"well text-center\" style=\"background-color: #f8f9fa; border-top: 4px solid #0056b3; padding: 30px 20px;\">\n                <h3 style=\"margin-top: 0; color: #333; margin-bottom: 15px;\">พบปัญหาหน้างานก่อสร้าง? ให้ทีมงานมืออาชีพดูแลคุณ</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    ไม่ว่าหน้างานจะยากแค่ไหน หรือมีอุปสรรคที่คาดไม่ถึง <strong>ธีรพงษ์เซอร์วิส</strong> มีทั้งเครื่องจักรหนักที่พร้อมลุย และทีมช่างประสบการณ์สูงที่พร้อมแก้ปัญหาหน้างานให้ลุล่วงตามแผนงาน \n                </p>\n                <div class=\"row\">\n                    <div class=\"col-sm-6\" style=\"margin-bottom: 15px;\">\n                        <a href=\"https://www.theeraphong.com/images/pile\" class=\"btn btn-primary btn-block btn-lg\" style=\"padding: 15px;\">\n                            <i class=\"fa fa-cogs\"></i> บริการกดเสาเข็มไมโครไพล์\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6\">\n                        <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-success btn-block btn-lg\" style=\"padding: 15px;\">\n                            <i class=\"fa fa-shield\"></i> บริการรับทำกำแพงกันดิน\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1710962864135948.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP3', '2021-09-15 10:22:19', '2021-09-15 10:30:48'),
(20, 'เขื่อนกันดินไทรม้า 19 EP.4', 'อัพเดทงานสร้างเขื่อนกันดิน ซอยไทรม้า 19', '<h1><strong>อัพเดทงาน กำแพงกันดิน ซอย ไทรม้า 19</strong></h1>\r\n\r\n<p>หน้างาน ทำกำแพงกันดิน ยังคงเนินการไปได้เรื่อย ๆ แต่ก็ประสบกับปัญหาหลัก ที่ทำให้ล่าช้า คือ หินที่อยู่ใต้น้ำที่มีค่อนข้างมาก รถแบคโฮ จึงต้องทำงานสองอย่าง คือ</p>\r\n\r\n<ol>\r\n	<li>เคลียหิน</li>\r\n	<li>กดเข็ม</li>\r\n</ol>\r\n\r\n<p>&nbsp;</p>\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/vmWXNdmQ6qM\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>\r\n<p>&nbsp;</p>\r\n\r\n<p>ทั้งนี้ทางทีมงานก็เร่งดำเนินการให้งานจบออกมา แล้วสามารถเสร็จทันตามกำหนดเวลา โดยยังคงไว้ซึ่งมาตรฐานที่เคยทำมาเป็นที่ตั้งสูงสุด</p>\r\n\r\n<p>โดยความคืบหน้าสามารถดำเนินการไปได้ มากกว่า 30% ของงานทั้งหมด&nbsp;</p>\r\n\r\n<blockquote>\r\n<p><strong>&quot;งานยากไม่ว่า เสียหน้า ธีรพงษ์ ไม่ยอม&quot;</strong></p>\r\n</blockquote>\r\n\r\n<p>รวมถึงแผ่นเสียบที่ใช้หล่อสดหน้างาน ซึ่งจะใช้เสียบเข้าระหว่างเสาเข็มเมื่อการกดเข็ม ไอ 22 ด้วยแบคโฮ แล้วเสร็จ สามารถดำเนินการไปได้มากกว่า 25%&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/17092021/saima-19-rw-170921-1.webp\" style=\"height:500px; width:375px\" /></p>', 'images/blogs/1711139361714176.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP4', '2021-09-17 09:07:41', '2021-09-17 09:07:41'),
(21, 'กำแพง กัน ดิน ซอยบางกร่าง45/5 EP.1', 'เริ่มงานทำกำแพงกันดิน ซอยบางกร่าง 45/5', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h2 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    Case Study: แก้ปัญหากำแพงกันดินริมคลองพังทลาย ซอยบางกร่าง 45/5 (Day 1)\n                </h2>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตข้อมูลหน้างานวันแรก | <i class=\"fa fa-map-marker\"></i> พิกัด: ติดริมคลองบางนางเกริก และคลองอ้อมน้อย จ.นนทบุรี\n                </p>\n            </div>\n\n            <p class=\"lead\" style=\"line-height: 1.8;\">\n                การสร้างกำแพงกันดินริมคลอง ถือเป็นหนึ่งในงานโครงสร้างที่ปราบเซียนและต้องอาศัยการคำนวณที่แม่นยำที่สุด วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> จะพาทุกท่านลงพื้นที่หน้างานจริงในวันแรก (Day 1) กับโปรเจกต์งานแก้ไขและสร้าง <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\">กำแพงกันดิน</a> ใหม่ทั้งหมด ณ ซอยบางกร่าง 45/5 ซึ่งพื้นที่แห่งนี้มีโจทย์ที่ท้าทายคือทำเลที่ตั้งติดกับ <strong>คลองบางนางเกริก และคลองอ้อมน้อย</strong> \n            </p>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/52523.jpg\" alt=\"สภาพแวดล้อมริมคลองบางนางเกริก คลองอ้อมน้อย ซอยบางกร่าง 45/5\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: บรรยากาศพื้นที่หน้างาน ติดริมคลองบางนางเกริกและคลองอ้อมน้อย ซึ่งมีระดับน้ำขึ้นลงและกระแสน้ำกัดเซาะตลอดเวลา</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                ความไว้วางใจจากลูกค้า: จุดเริ่มต้นของการแก้ปัญหา\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ก่อนที่จะเริ่มเจาะลึกถึงเนื้องาน ทางทีมงานธีรพงษ์เซอร์วิส ต้องขอขอบพระคุณ <strong>คุณพี่มนัส</strong> เจ้าของพื้นที่เป็นอย่างสูง ที่ให้ความไว้วางใจและเลือกใช้บริการทีมช่างของเราให้เข้ามาดูแลโปรเจกต์นี้ เพื่อคืนความปลอดภัยและทัศนียภาพที่สวยงามให้กับพื้นที่ริมคลองแห่งนี้อีกครั้ง\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                วิเคราะห์โครงสร้าง: ทำไมกำแพงกันดินเดิมถึงล้มพัง?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เมื่อทีมวิศวกรและช่างของเราลงพื้นที่สำรวจ ได้พบกับโครงสร้างกำแพงกันดินเดิมที่อยู่ในสภาพ <strong>\"ชำรุดเสียหายหนักและเอนล้มลงไปทางฝั่งแม่น้ำ\"</strong> ซึ่งจากประสบการณ์งานช่างของเรา สามารถวิเคราะห์สาเหตุหลักของการพังทลายในครั้งนี้ได้ชัดเจนครับ:\n            </p>\n            \n            <div class=\"alert alert-warning\" style=\"margin-top: 20px; border-left: 5px solid #d9534f;\">\n                <h4 style=\"color: #d9534f; margin-top: 0;\"><i class=\"fa fa-exclamation-triangle\"></i> สาเหตุหลักที่ทำให้กำแพงกันดินริมคลองพัง</h4>\n                <p style=\"margin-bottom: 0; line-height: 1.6;\">\n                    ปัญหาไม่ได้อยู่ที่ตัวกำแพงด้านหน้า แต่อยู่ที่ <strong>\"ระบบสเตย์ (Stay) หรือคานดึงรั้งด้านหลัง\"</strong> ของกำแพงเดิม มีการออกแบบขนาดที่ <strong>\"เล็กและตื้นเกินไป\"</strong> เมื่อต้องเผชิญกับแรงดันมหาศาลจากมวลดินด้านใน ประกอบกับการถูกกระแสน้ำในคลองกัดเซาะผิวดินด้านนอก ทำให้ระบบสเตย์เดิมสูญเสียแรงเสียดทานและไม่มีความแข็งแรงเพียงพอที่จะดึงรั้งกำแพงเอาไว้ได้ กำแพงจึงแบะและล้มพังลงสู่คลองในที่สุด\n                </p>\n            </div>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/52520.jpg\" alt=\"สภาพกำแพงกันดินริมคลองที่ทรุดและพังทลาย เนื่องจากสเตย์ยึดกำแพงมีขนาดเล็กเกินไป\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2: สภาพความเสียหายของกำแพงกันดินเดิม ที่ล้มเอนลงไปทางฝั่งแม่น้ำจากปัญหาโครงสร้างสเตย์ไม่ได้มาตรฐาน</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                ภารกิจของเรา: การรื้อถอนและวางระบบกำแพงกันดินใหม่ (เต็มระบบ)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                โจทย์ของทีมงานธีรพงษ์เซอร์วิสในโปรเจกต์นี้ ไม่ใช่แค่การซ่อมแซม แต่คือการ <strong>\"รื้อและสร้างระบบกำแพงกันดินสเตย์ใหม่ทั้งหมด\"</strong> เพื่อให้มั่นใจว่าจะไม่เกิดเหตุการณ์ซ้ำรอยเดิมอีก โดยเราจะเน้นหนักไปที่การขยายขนาดของคานสเตย์ การลงเข็มสเตย์ให้ลึกทะลุชั้นดินอ่อน และผูกเหล็กโครงสร้างให้เป็นเนื้อเดียวกัน (Monolithic) ทนทานต่อแรงต้านของน้ำและดินริมคลองได้อย่างเด็ดขาด\n            </p>\n\n            <p style=\"line-height: 1.8; font-size: 16px; margin-bottom: 20px;\">\n                เชิญรับชมวิดีโอบรรยากาศการประเมินหน้างานในวันแรก และแผนการเตรียมพื้นที่ก่อนลงมือทำงานจริงของทีมงานเราได้ที่คลิปด้านล่างนี้ครับ:\n            </p>\n\n            <div class=\"embed-responsive embed-responsive-16by9\" style=\"margin: 30px 0; border-radius: 8px; overflow: hidden; box-shadow: 0 6px 15px rgba(0,0,0,0.15);\">\n                <iframe class=\"embed-responsive-item\" src=\"https://www.youtube.com/embed/bXvRyK0OZj4\" allowfullscreen title=\"วิดีโอสำรวจหน้างาน กำแพงกันดินพัง ซอยบางกร่าง 45/5\"></iframe>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px; margin-top: 20px; font-weight: bold; text-align: center;\">\n                รอติดตามชมรายละเอียดขั้นตอนการดำเนินการใน EP. ถัดไป มาคอยดูกันครับว่าทางทีมงานเราจะมีเทคนิคและวิธีการจัดการกับหน้างานที่ท้าทายนี้อย่างไรบ้าง!\n            </p>\n\n            <hr style=\"margin: 40px 0;\">\n\n            <div class=\"well text-center\" style=\"background-color: #f8f9fa; border: none; padding: 30px 20px;\">\n                <h3 style=\"margin-top: 0; color: #333; margin-bottom: 20px;\">สนใจผลงาน หรือต้องการปรึกษาปัญหาเรื่องงานช่าง?</h3>\n                \n                <div class=\"row\">\n                    <div class=\"col-sm-6\" style=\"margin-bottom: 15px;\">\n                        <a href=\"https://www.theeraphong.com/images/retaining-wall\" class=\"btn btn-primary btn-block btn-lg\" style=\"white-space: normal; padding: 15px;\">\n                            <i class=\"fa fa-picture-o\"></i> ดูรวมรูปภาพผลงานกำแพงกันดินทั้งหมด\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6\">\n                        <a href=\"https://www.theeraphong.com/blog\" class=\"btn btn-info btn-block btn-lg\" style=\"white-space: normal; padding: 15px; background-color: #17a2b8; border-color: #17a2b8;\">\n                            <i class=\"fa fa-book\"></i> อ่านบทความและข่าวสารล่าสุดของเรา\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1711320597112563.webp', 10, 'กำแพงกันดิน-ซอยบางกร่าง45-5-EP1', '2021-09-19 08:43:10', '2021-09-20 00:35:42'),
(22, 'เขื่อนกันดินไทรม้า 19 EP.5', 'อัพเดทงานสร้างเขือนกันดิน ซอยไทรม้า 19 ณ 20 ก.ย. 2564', '<p><strong>อัพเดทงาน ณ วันที่ 20 กันยายน 2564</strong></p>\r\n\r\n<p>วันนี้ ทีมงาน <a href=\"https://www.theeraphong.com/\">ธีรพงษ์ เซอร์วิส</a>&nbsp;ได้ดำเนินการกดเสาเข็ม กำแพง กัน ดิน ทั้งในส่วนของกำแพง และสเตย์ เป็นอันเสร็จเรียบร้อย รวมเป็นจำนวนทั้งสิ้น 110 ต้น</p>\r\n\r\n<p><img alt=\"แม็คโคร กดเข็ม\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/180921/180921-4.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>รูป แม็คโคร กดเข็ม</p>\r\n\r\n<p>ทั้งนี้ การดำเนินการอาจมีความล่าช้าไปบ้างเล็กน้อยจากการคาดการณ์ไว้ เนื่องจากประสบกับปัญหาเศษหินที่อยู่ใต้น้ำ และสภาพอากาศที่ไม่สามารถควบคุมได้</p>\r\n\r\n<p><img alt=\"เศษหินใต้ดิน\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/180921/180921-1.webp\" style=\"height:500px; width:375px\" /></p>\r\n\r\n<p>รูป หินที่เป็นอุปสรรคหลักสำหรับงานกำแพง กัน ดิน</p>\r\n\r\n<p>แต่ในภาพรวม ก็ยังสามารถดำเนินการไปได้ด้วยดี ทั้งนี้ต้องรอระยะเวลาอีกประมาณ 3 วันเพื่อให้เสาเข็มยึดกับดินได้ดียิ่งขึ้น และจะได้ทำการติดตั้งแผ่นกำแพงกันดินอีกครั้ง ทั้งนี้เสาเข็มไอ 22 ความยาว 10 เมตร ได้ถูกกดลงไปใต้พื้นดินมากกว่ากว่า 8 เมตร ซึ่งสามารถมั่นใจได้ว่า กำแพง กัน ดิน ที่ทางทีมงานเราสร้าง มีความคงทน และแข็งแรงอย่างแน่นอน</p>\r\n\r\n<p><img alt=\"แม็คโครขนย้ายเสาเข็มไอ 22\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/180921/180921-2.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>รูป แม็คโครกำลังดำเนินการย้ายเสาเข็มสู่ตำแหน่งที่กำหนด</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>ซึ่งหลังจากนี้ประมาณ 3 วัน ทีมงานจะทำการเสียบแผ่นกำแพงกันดิน แล้วทางทีมงานจะได้ทำการอัพเดทให้ได้ชมในเวลาต่อไป</p>\r\n\r\n<p>อัพเดทงาน ครั้งก่อนหน้า <a href=\"https://www.theeraphong.com/blog/20\">คลิ๊กที่นี่</a></p>\r\n\r\n<p>งานอื่น ๆ <a href=\"https://www.theeraphong.com/\">คลิ๊กที่นี่</a></p>\r\n\r\n<p>&nbsp;</p>', 'images/blogs/1711438109246937.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP5', '2021-09-20 16:12:41', '2021-09-20 16:16:08');
INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(23, 'สำรวจกำแพง กั้น ดิน พัง สุพรรณบุรี', 'ลงพื้นหน้าดูหน้างาน สำรวจกำแพง กั้น ดินพัง', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    Case Study: สำรวจวิกฤตหน้างาน กำแพงกั้นดินพังทลาย ริมแม่น้ำท่าจีน จ.สุพรรณบุรี พร้อมวิเคราะห์สาเหตุเชิงลึก\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-exclamation-triangle\"></i> อัปเดตการสำรวจหน้างานฉุกเฉิน | <i class=\"fa fa-map-marker\"></i> พิกัด: พื้นที่ติดริมแม่น้ำท่าจีน จังหวัดสุพรรณบุรี\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #fcf8e3; padding: 25px; border-left: 5px solid #f0ad4e; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    ปัญหา <strong>\"ตลิ่งทรุด\"</strong> และ <strong>\"กำแพงกันดินพัง\"</strong> ถือเป็นฝันร้ายที่สุดสำหรับผู้ที่มีบ้านหรือที่ดินติดริมแม่น้ำ วันนี้ทีมงานวิศวกรและช่างผู้ชำนาญการจาก <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ได้รับความไว้วางใจให้ลงพื้นที่ด่วน เพื่อประเมินความเสียหายและหาทางแก้ไขปัญหาหน้างานจริง ณ จังหวัดสุพรรณบุรี ซึ่งเหตุการณ์นี้ได้สร้างความเสียหายอย่างหนักให้กับโครงสร้างริมน้ำ บทความนี้เราจะพาไปวิเคราะห์เจาะลึกว่า <em>ทำไมกำแพงถึงพัง?</em> และ <em>เราจะมีวิธีแก้ปัญหาระยะยาวอย่างไรไม่ให้ซ้ำรอยเดิม?</em>\n                </p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. สำรวจความเสียหาย: วิกฤตแนวกำแพงกั้นดินพังถล่มลงสู่แม่น้ำ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เมื่อทีมงานของเราเดินทางไปถึงพื้นที่หน้างานที่ติดกับ <strong>แม่น้ำท่าจีน</strong> ภาพที่ปรากฏคือแนวกำแพงกันดินคอนกรีตเดิม ได้เกิดการทรุดตัวและพังทลายลงไปทางฝั่งแม่น้ำเป็นแนวยาวตลอดขอบแนวเขตที่ดิน แรงดึงจากการถล่มของกำแพงได้กระชากเอาพื้นดินด้านบนและสิ่งปลูกสร้างรอบข้างให้สไลด์ตามลงไปด้วย\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/220921/suphan-220921-1.webp\" alt=\"สภาพกำแพงกั้นดินพังทลาย ริมแม่น้ำท่าจีน จ.สุพรรณบุรี\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: สภาพแนวกำแพงกั้นดินเดิมที่สูญเสียความสามารถในการรับน้ำหนัก และพังทลายลงสู่แม่น้ำท่าจีน</em></p>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                สิ่งที่น่าเสียดายที่สุดในเหตุการณ์นี้ คือบริเวณจุดที่เกิดการพังทลายอย่างหนัก เป็นที่ตั้งของ <strong>\"บ้านต้นไม้ (Treehouse)\"</strong> ซึ่งเป็นมุมพักผ่อนที่สวยงามของลูกค้า โครงสร้างบ้านต้นไม้ได้รับผลกระทบโดยตรงจากการที่รากฐานดินถูกกัดเซาะจนล้มพังลงมา สร้างความเสียหายทั้งในด้านทรัพย์สินและคุณค่าทางจิตใจต่อเจ้าของพื้นที่เป็นอย่างมาก\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/220921/suphan-220921-3.webp\" alt=\"บ้านต้นไม้พังเสียหายจากเหตุกำแพงกันดินทรุดตัว\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2: ความเสียหายที่เกิดขึ้นกับบ้านต้นไม้ ซึ่งตั้งอยู่ใกล้แนวตลิ่งที่เกิดการสไลด์ตัว</em></p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. เจาะลึกทางวิศวกรรม: ทำไมกำแพงกั้นดินริมแม่น้ำถึงล้มพัง?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                การสร้าง <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\" style=\"color: #0056b3; font-weight: bold;\">กำแพงกันดิน (Retaining Wall)</a> ริมแม่น้ำใหญ่ ถือเป็นงานที่ปราบเซียนที่สุดในบรรดางานโครงสร้างทั้งหมด เพราะต้องต่อสู้กับแรงดันมหาศาลจากทั้ง 2 ฝั่ง (ฝั่งดินและฝั่งน้ำ) จากการลงพื้นที่ประเมินเบื้องต้น ทีมงานวิเคราะห์สาเหตุหลักของการพังทลายไว้ 3 ประเด็นหลัก ดังนี้ครับ:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-4\">\n                    <div class=\"panel panel-danger text-center\">\n                        <div class=\"panel-heading\"><h4 style=\"margin: 0; font-weight: bold;\"><i class=\"fa fa-tint\"></i> แรงกัดเซาะของกระแสน้ำ</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; text-align: left; line-height: 1.6;\">\n                            แม่น้ำท่าจีนมีระดับน้ำขึ้น-ลง และกระแสน้ำไหลเชี่ยวในช่วงฤดูน้ำหลาก หากปลายเสาเข็มกำแพงเดิมไม่ได้หยั่งลึกลงไปเกินกว่า <strong>\"ระดับท้องน้ำที่ถูกกัดเซาะลึกสุด (Scour Depth)\"</strong> กระแสน้ำจะพัดพาดินใต้ท้องกำแพงออกไป ทำให้กำแพงลอยและล้มลง\n                        </div>\n                    </div>\n                </div>\n                <div class=\"col-md-4\">\n                    <div class=\"panel panel-danger text-center\">\n                        <div class=\"panel-heading\"><h4 style=\"margin: 0; font-weight: bold;\"><i class=\"fa fa-anchor\"></i> ขาดระบบสเตย์ (Stay Beam)</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; text-align: left; line-height: 1.6;\">\n                            กำแพงกั้นดินริมน้ำที่มีความสูงเกิน 1.5 เมตร <strong>จำเป็นต้องมีคานและเสาเข็มสเตย์ด้านหลัง</strong> เพื่อทำหน้าที่ดึงรั้งกำแพงหน้าเอาไว้ หากโครงสร้างเดิมเป็นเพียงกำแพงเสียบแผ่นปูนเปล่าๆ จะไม่สามารถต้านทานแรงดันดินด้านข้าง (Lateral Earth Pressure) ได้เลย\n                        </div>\n                    </div>\n                </div>\n                <div class=\"col-md-4\">\n                    <div class=\"panel panel-danger text-center\">\n                        <div class=\"panel-heading\"><h4 style=\"margin: 0; font-weight: bold;\"><i class=\"fa fa-sort-amount-desc\"></i> แรงดันน้ำสะสมหลังกำแพง</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; text-align: left; line-height: 1.6;\">\n                            ในช่วงที่ฝนตกหนัก น้ำที่ซึมลงดินจะพยายามหาทางออกสู่แม่น้ำ หากกำแพงกันดินไม่มีระบบรูระบายน้ำ (Weep Holes) ที่มีประสิทธิภาพ น้ำจะขังอยู่หลังกำแพง ก่อให้เกิด <strong>แรงดันอุทกสถิต (Hydrostatic Pressure)</strong> ซึ่งมีพลังมหาศาลพอที่จะผลักให้กำแพงคอนกรีตฉีกขาดได้\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ก้าวต่อไป: แผนการกู้คืนและแนวทางแก้ไขปัญหาระยะยาว (Long-term Solution)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากสำรวจมิติของความเสียหาย ถ่ายภาพ และเก็บข้อมูลระดับความสูงของชั้นดินอย่างละเอียดเสร็จสิ้น ภารกิจต่อไปของทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> คือการกลับไปออกแบบโครงสร้างใหม่ร่วมกับทีมวิศวกร เพื่อนำเสนอโซลูชันที่ดีที่สุดให้กับคุณลูกค้า โดยมีแนวทางการแก้ไขปัญหาเบื้องต้นดังนี้:\n            </p>\n\n            <ul class=\"list-group\" style=\"font-size: 16px; margin-top: 20px;\">\n                <li class=\"list-group-item\" style=\"padding: 15px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">1. การเคลียร์พื้นที่และรื้อถอน (Clearing & Demolition)</h4>\n                    <p style=\"margin-bottom: 0;\">ต้องนำเครื่องจักรเข้ามารื้อถอนเศษซากกำแพงเดิมและซากบ้านต้นไม้ที่จมอยู่ริมน้ำออกให้หมดก่อน เพื่อลดน้ำหนักกดทับบริเวณตลิ่ง และเปิดทางให้สามารถตอกเสาเข็มใหม่ได้</p>\n                </li>\n                <li class=\"list-group-item\" style=\"padding: 15px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">2. การวางระบบรากฐานใหม่ \"แบบเต็มระบบ\" (Full Retaining System)</h4>\n                    <p style=\"margin-bottom: 0;\">เราจะนำเสนอการใช้ <strong>เสาเข็มไมโครไพล์ (Micropile) ชนิด I-Shape</strong> ที่มีความยาวเพียงพอที่จะทะลุผ่านชั้นดินเลนริมแม่น้ำ ลงไปยึดเกาะกับชั้นดินเหนียวแข็งด้านล่าง พร้อมเสริมความมั่นคงด้วย <strong>\"ระบบเสาเข็มและคานสเตย์ดึงรั้ง\"</strong> เพื่อป้องกันการล้มแบะ 100%</p>\n                </li>\n                <li class=\"list-group-item\" style=\"padding: 15px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">3. งานป้องกันการกัดเซาะ (Erosion Control)</h4>\n                    <p style=\"margin-bottom: 0;\">ออกแบบระบบร่องระบายน้ำและ Weep Holes ให้เหมาะสม เพื่อลดแรงดันน้ำจากฝั่งตัวบ้าน พร้อมแนะนำการเรียงหินป้องกันการกัดเซาะที่บริเวณตีนกำแพงฝั่งแม่น้ำ</p>\n                </li>\n            </ul>\n\n            <p style=\"line-height: 1.8; font-size: 16px; margin-top: 25px; font-weight: bold; color: #333; text-align: center;\">\n                รอติดตามชมความคืบหน้าและการพลิกโฉมแก้ไขปัญหากำแพงกั้นดินริมแม่น้ำท่าจีนโปรเจกต์นี้ ได้ในบทความอัปเดตตอนต่อไปครับ!\n            </p>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> ถาม-ตอบ (FAQ) เมื่อพบปัญหากำแพงริมน้ำพังทลาย</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: เมื่อเห็นกำแพงเริ่มเอียง หรือมีรอยแตกร้าวริมแม่น้ำ ควรทำอย่างไรเป็นอันดับแรก?</h4>\n                <p style=\"margin-bottom: 20px;\">A: สิ่งแรกคือ <strong>\"ความปลอดภัย\"</strong> ครับ ห้ามให้คนหรือสัตว์เลี้ยงเข้าใกล้บริเวณนั้นเด็ดขาด เพราะดินอาจสไลด์ตามลงไปได้ทุกเมื่อ จากนั้นควรรีบติดต่อวิศวกรหรือผู้รับเหมาที่มีประสบการณ์ด้านกำแพงกันดินโดยตรง ให้เข้ามาประเมินความเสี่ยงและหาทางค้ำยันชั่วคราวครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: กำแพงเดิมพัง สามารถเทปูนซ่อมแซมรอยแตกได้หรือไม่?</h4>\n                <p style=\"margin-bottom: 20px;\">A: <strong>ไม่แนะนำครับ</strong> การที่กำแพงเอียงหรือพังทลาย เป็นสัญญาณว่า \"ฐานราก (เสาเข็ม) ด้านล่างได้สูญเสียกำลังรับน้ำหนักไปแล้ว\" การเทปูนฉาบหรือต่อเติมด้านบน จะยิ่งเป็นการเพิ่มน้ำหนักให้ตลิ่งทรุดเร็วขึ้น การแก้ปัญหาที่ถูกต้องคือต้องรื้อและวางระบบเสาเข็มใหม่เท่านั้นครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: สร้างกำแพงกันดินริมแม่น้ำ ต้องขออนุญาตกรมเจ้าท่าหรือไม่?</h4>\n                <p>A: หากแนวกำแพงของคุณมีการล่วงล้ำลงไปในแนวน่านน้ำ หรืออยู่ติดชิดขอบเขตแหล่งน้ำสาธารณะ จำเป็นต้องมีการตรวจสอบโฉนดและยื่นขออนุญาตจากกรมเจ้าท่าและเทศบาลในพื้นที่ให้ถูกต้องตามกฎหมายก่อนเริ่มดำเนินการก่อสร้างครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #d9534f; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">ปัญหาตลิ่งพัง กำแพงทรุด ปรึกษาเราก่อนสายเกินแก้</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    อย่าปล่อยให้ปัญหาโครงสร้างริมน้ำลุกลามจนสร้างความเสียหายแก่บ้านและทรัพย์สินของคุณ <br>\n                    <strong>ธีรพงษ์เซอร์วิส</strong> มีทีมวิศวกรและช่างผู้ชำนาญการ พร้อมลงพื้นที่ประเมินหน้างานจริงเพื่อหาทางออกที่ยั่งยืน\n                </p>\n                \n                <div class=\"row\">\n                    <div class=\"col-sm-6 text-right\">\n                        <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-danger btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px;\">\n                            <i class=\"fa fa-shield\"></i> บริการรับทำกำแพงกันดิน-เขื่อน\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6 text-left\">\n                        <a href=\"https://www.theeraphong.com/blog\" class=\"btn btn-info btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px; background-color: #17a2b8; border-color: #17a2b8;\">\n                            <i class=\"fa fa-book\"></i> รวมข่าวสารและบทความงานช่าง\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1711592918414737.webp', 10, 'สำรวจกำแพงกั้นดินพัง-สุพรรณบุรี', '2021-09-22 09:15:43', '2021-09-22 09:16:46'),
(24, 'เขื่อนกันดินไทรม้า 19 EP.6', 'ความคืบหน้างานเขือนกันดิน ซอยไทรม้า 19', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h2 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    เจาะลึกงานโครงสร้าง: อัปเดตความคืบหน้า งานติดตั้งแผ่นเสียบ กำแพงกันดิน ลึก 1.50 เมตร โครงการซอยบางกร่าง 45/5\n                </h2>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตข้อมูลหน้างาน ณ วันที่ 27 กันยายน 2564 | <i class=\"fa fa-folder-open\"></i> หมวดหมู่: อัปเดตผลงานหน้างาน, ความรู้งานก่อสร้าง\n                </p>\n            </div>\n\n            <p class=\"lead\" style=\"line-height: 1.8;\">\n                การปกป้องหน้าดินจากการพังทลายและการทรุดตัว ถือเป็นหัวใจสำคัญของการปลูกสร้างบ้านและอาคาร โดยเฉพาะในพื้นที่ที่มีสภาพดินอ่อน ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ขอพาทุกท่านมาติดตามความคืบหน้าอย่างใกล้ชิด กับโครงการก่อสร้าง <strong>กำแพงกันดิน</strong> ณ พื้นที่ซอยบางกร่าง 45/5 จังหวัดนนทบุรี ซึ่งล่าสุดทางทีมวิศวกรและช่างผู้ชำนาญการของเราได้ดำเนินการ <strong>\"กดแผ่นเสียบคอนกรีตเสริมเหล็ก\"</strong> เสร็จสิ้นเรียบร้อยแล้วตามแผนงานที่วางไว้ บทความนี้เราจะพาไปเจาะลึกถึงเหตุผลทางวิศวกรรมว่าทำไมเราถึงต้องให้ความสำคัญกับขั้นตอนนี้นัก\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/52540.jpg\" alt=\"การติดตั้งแผ่นเสียบกำแพงกันดิน ลึก 1.5 เมตร ซอยบางกร่าง นนทบุรี\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 900px; box-shadow: 0 6px 15px rgba(0,0,0,0.15);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: ทีมช่างธีรพงษ์เซอร์วิส ควบคุมการกดแผ่นเสียบกำแพงกันดินด้วยเครื่องจักรมาตรฐาน ลึกลงไป 1.50 เมตร</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. วิเคราะห์สภาพดินและโจทย์ของโครงการ ซอยบางกร่าง 45/5\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                พื้นที่ในเขตจังหวัดนนทบุรีและปริมณฑลส่วนใหญ่ มีลักษณะทางธรณีวิทยาเป็น <strong>\"ชั้นดินเหนียวอ่อน (Soft Clay)\"</strong> ซึ่งมีความเสี่ยงสูงต่อการสไลด์ตัวของดินเมื่อมีความชื้นสูง หรือเมื่อมีการถมดินใหม่เพื่อปรับระดับพื้นที่ โครงการนี้เจ้าของบ้านมีความต้องการที่จะปรับระดับผิวดินให้สูงขึ้นเพื่อป้องกันปัญหาน้ำท่วมขังและเพิ่มพื้นที่ใช้สอย \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ดังนั้น การสร้างเพียงรั้วบ้านธรรมดาจึงไม่สามารถตอบโจทย์แรงดันที่มหาศาลจากดินถมใหม่ได้ หากฝืนทำไป รั้วอาจเกิดการแตกร้าว เอนเอียง หรือพังทลายในเวลาเพียงไม่กี่ปี ทางทีมงานจึงได้ออกแบบโครงสร้างเป็นระบบ <strong>กำแพงกันดิน (Retaining Wall)</strong> แบบเต็มระบบ เพื่อรับมือกับปัญหานี้อย่างเด็ดขาด\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. ทำไมต้องกดแผ่นเสียบลึกลงไปถึง 1.50 เมตร?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ในงานวิศวกรรมโยธา ความลึกของการฝังรากฐานเปรียบเสมือนการหยั่งรากแก้วของต้นไม้ใหญ่ ทีมงานของเราได้ลงพื้นที่สำรวจ คำนวณ และตัดสินใจกดแผ่นเสียบคอนกรีตอัดแรงฝังลึกลงไปใต้ระดับผิวดินเดิมถึง <strong>1.50 เมตร</strong> ด้วยเหตุผลทางเทคนิคดังต่อไปนี้:\n            </p>\n            \n            <div class=\"row\" style=\"margin-top: 20px;\">\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-default\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title text-primary\"><i class=\"fa fa-shield\"></i> การต้านทานแรงดันดินด้านข้าง</h4></div>\n                        <div class=\"panel-body\">\n                            <p>แรงดันดินด้านข้าง (Lateral Earth Pressure) คือศัตรูตัวฉกาจของกำแพง การฝังแผ่นเสียบลึก 1.5 เมตร จะช่วยเพิ่มพื้นที่สัมผัสใต้ดิน สร้างมวลต้านทาน (Passive Pressure) ที่แข็งแกร่งพอที่จะยันแผ่นดินถมใหม่ไม่ให้ผลักกำแพงล้ม</p>\n                        </div>\n                    </div>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-default\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title text-primary\"><i class=\"fa fa-tint\"></i> การป้องกันการกัดเซาะจากน้ำ</h4></div>\n                        <div class=\"panel-body\">\n                            <p>ในช่วงฤดูฝน น้ำที่ซึมลงดินจะทำให้ดินสูญเสียแรงเสียดทาน (Friction) การฝังโครงสร้างลึกผ่านชั้นดินร่วนซุยลงไปถึงชั้นดินที่แน่นกว่า จะช่วยป้องกันปัญหาดินสไลด์ลอดใต้ท้องกำแพง (Piping Effect) ได้อย่างมีประสิทธิภาพ</p>\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ความชัดเจนในเอกสาร: จากแบบแปลนสู่หน้างานจริง\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ที่ <strong>ธีรพงษ์เซอร์วิส</strong> เราเชื่อว่างานรับเหมาก่อสร้างที่มีคุณภาพ ต้องมาพร้อมกับความโปร่งใสที่ตรวจสอบได้ การทำงานของเราเริ่มต้นตั้งแต่การจัดทำเอกสารข้อเสนอโครงการ (Proposal) ที่ระบุขอบเขตงานอย่างละเอียด สัญญาว่าจ้างที่รัดกุม และเอกสารการเบิกจ่าย (Payment Documents) ที่แบ่งงวดงานอย่างเป็นธรรม \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ตัวเลขความลึก 1.50 เมตร หรือสเปกของคอนกรีตและเหล็กเส้น ไม่ได้เป็นเพียงการกะเกณฑ์หน้างาน แต่ถูกระบุไว้อย่างชัดเจนในเอกสารประเมินราคา (BOQ) ลูกค้าจึงสามารถตรวจสอบและมั่นใจได้ว่า ทุกงวดงานที่ชำระเงิน จะได้รับผลงานที่ตรงปก ได้มาตรฐานทางวิศวกรรม วัสดุไม่ขาด ไม่มีการลดสเปก เพื่อโครงสร้างที่อยู่คู่บ้านไปอีกนับสิบปี\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/110516.jpg\" alt=\"การเตรียมงานผูกเหล็กคานทับหลังและคานสเตย์\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 900px; box-shadow: 0 6px 15px rgba(0,0,0,0.15);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2: แผนการดำเนินงานขั้นต่อไป คือการเตรียมพื้นที่สำหรับผูกเหล็กคานทับหลังและคานสเตย์</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. ก้าวต่อไป: โครงสร้างคานรัดหัวและระบบคานสเตย์ (Stay Beam)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากแผ่นเสียบและเสาเข็มถูกติดตั้งและยึดลงดินอย่างมั่นคงแล้ว ขั้นตอนต่อไปที่ทีมงานช่างของเราจะเร่งดำเนินการ คือการ <strong>ผูกเหล็กและเทคอนกรีตคาน</strong> ซึ่งเป็นองค์ประกอบที่ขาดไม่ได้เลยในระบบกำแพงกันดินที่สมบูรณ์แบบ โดยจะแบ่งออกเป็น 2 ส่วนหลักๆ ได้แก่:\n            </p>\n            \n            <ul class=\"list-group\" style=\"margin-top: 25px; font-size: 16px;\">\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 class=\"list-group-item-heading text-primary\" style=\"font-weight: bold;\"><i class=\"fa fa-cubes\"></i> คานทับหลัง (Top Beam) หรือคานรัดหัวเสา</h4>\n                    <p class=\"list-group-item-text\" style=\"line-height: 1.6; margin-top: 10px;\">ทำหน้าที่เป็นตัวประสาน เสาเข็มและแผ่นเสียบทุกชิ้นให้เชื่อมต่อเป็นโครงสร้างเดียวกัน (Monolithic Structure) ช่วยกระจายน้ำหนักและแรงสั่นสะเทือนไปตลอดแนวระนาบของกำแพง ป้องกันไม่ให้แผ่นเสียบแผ่นใดแผ่นหนึ่งรับภาระหนักเกินไปจนเกิดการปริแตก</p>\n                </li>\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 class=\"list-group-item-heading text-primary\" style=\"font-weight: bold;\"><i class=\"fa fa-anchor\"></i> คานสเตย์ (Stay Beam) และเสาสเตย์</h4>\n                    <p class=\"list-group-item-text\" style=\"line-height: 1.6; margin-top: 10px;\">นี่คือเคล็ดลับความแข็งแกร่ง! คานสเตย์คือระบบคานดึงรั้งที่ซ่อนอยู่ใต้ดิน ทำหน้าที่เหมือน \"รากแก้ว\" หรือ \"สมอเรือ\" ที่ช่วยดึงรั้งตัวกำแพงแนวหน้าเอาไว้กับผืนดินด้านใน ป้องกันปัญหาพบบ่อยอย่าง \'กำแพงล้มหรือแบะออกด้านนอก\' เมื่อมีแรงดันมหาศาลจากดินและน้ำฝนสะสม</p>\n                </li>\n            </ul>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 40px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> คำถามที่พบบ่อย (FAQ) เกี่ยวกับการทำกำแพงกันดิน</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: การทำกำแพงกันดิน ใช้ระยะเวลาดำเนินการนานหรือไม่?</h4>\n                <p style=\"margin-bottom: 20px;\">A: ระยะเวลาขึ้นอยู่กับความยาวและสภาพหน้างานครับ สำหรับหน้างานทั่วไปความยาว 20-30 เมตร อาจใช้เวลาประมาณ 15-20 วันทำการ รวมระยะเวลาการรอให้คอนกรีตเซ็ตตัว (Curing Time) เพื่อให้ได้ความแข็งแรงตามมาตรฐาน</p>\n\n                <h4 style=\"font-weight: bold;\">Q: หน้างานเป็นซอยแคบ เครื่องจักรใหญ่เข้าไม่ได้ สามารถทำได้หรือไม่?</h4>\n                <p style=\"margin-bottom: 20px;\">A: สามารถทำได้ครับ ทางธีรพงษ์เซอร์วิสมีทีมงานประเมินหน้างาน หากเป็นซอยแคบอย่างในบางพื้นที่ของนนทบุรี เรามีเครื่องจักรขนาดเล็ก (Mini Excavator) และเทคนิคการกดเข็มแบบไฮดรอลิกที่ออกแบบมาเพื่อพื้นที่จำกัดโดยเฉพาะ ลดผลกระทบต่อเพื่อนบ้านครับ</p>\n                \n                <h4 style=\"font-weight: bold;\">Q: ค่าใช้จ่ายในการทำกำแพงกันดิน ประเมินจากอะไร?</h4>\n                <p>A: ประเมินจากความยาว (เมตร) ความสูงของดินที่ต้องการถม และสภาพดินเดิมครับ เรายินดีเข้าไปสำรวจหน้างานจริง วัดพื้นที่ และออกใบเสนอราคาให้พิจารณาก่อนตัดสินใจ โดยไม่มีค่าใช้จ่ายแอบแฝงครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-left: 6px solid #0056b3; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #0056b3;\">ปกป้องพื้นที่ของคุณด้วยโครงสร้างที่ได้มาตรฐาน</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    โครงสร้างที่ผสานกันอย่างลงตัว ทั้งการเลือกใช้เสาเข็มที่เหมาะสม แผ่นเสียบที่ฝังลึก 1.5 เมตร คานรัดหัว และระบบคานสเตย์ จะทำให้กำแพงกันดินของท่านมีความมั่นคง พร้อมรับมือกับทุกสภาพอากาศและแรงดันหน้าดินในระยะยาว<br><br>\n                    หากท่านกำลังมองหาผู้รับเหมาที่มีประสบการณ์ ตรงไปตรงมา และมีเอกสารสัญญารัดกุม <strong>ธีรพงษ์เซอร์วิส</strong> พร้อมให้บริการท่านครับ\n                </p>\n                <a href=\"/retaining-wall\" class=\"btn btn-primary btn-lg\" style=\"padding: 15px 30px; font-size: 18px; border-radius: 30px; text-transform: uppercase; font-weight: bold; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                    <i class=\"fa fa-hand-o-right\"></i> ดูบริการรับทำกำแพงกันดิน และขอประเมินราคาฟรี!\n                </a>\n            </div>\n\n        </div>\n    </div>\n</div>\n<img alt=\"\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/270921/saima-1.webp\" style=\"height:500px; width:375px\" />\n\n<p>งานก่อนหน้า <a href=\"https://www.theeraphong.com/blog/22\">คลิ๊กที่นี่</a></p>\n\n<p>รายละเอียดงานกำแพงกันดิน <a href=\"https://www.theeraphong.com/retaining-wall\">คลิ๊กที่นี่&nbsp;</a></p>', 'images/blogs/1712044835626349.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP6', '2021-09-27 08:59:48', '2021-09-27 08:59:48'),
(25, 'กำแพง กัน ดิน ซอยบางกร่าง45/5 EP.2', 'อัพเดทงาน กำแพง กัน ดิน ในซอยบางกร่าง 45', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    อัปเดตงานฐานรากเขื่อนกันดิน: ลำเลียงเสาเข็มไอ (I-Shape) 10 เมตร 110 ต้น และเตรียมงานหล่อแผ่นเสียบ\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตข้อมูลหน้างาน ณ วันที่ 14 กันยายน 2561 | <i class=\"fa fa-folder-open\"></i> หมวดหมู่: ความรู้งานฐานราก, เขื่อนกันดินริมน้ำ\n                </p>\n            </div>\n\n            <p class=\"lead\" style=\"line-height: 1.8;\">\n                ก้าวเข้าสู่ช่วงสำคัญของงานโครงสร้าง! วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ขอพาทุกท่านมาเจาะลึกเบื้องหลังการทำงานในเฟสของ <strong>\"งานฐานราก (Foundation Phase)\"</strong> สำหรับโปรเจกต์สร้างเขื่อนและ <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\">กำแพงกันดิน</a> ซึ่งถือเป็นหัวใจหลักที่จะกำหนดความแข็งแรงของโครงสร้างทั้งหมด บทความนี้เราจะพาไปดูการบริหารจัดการวัสดุชิ้นใหญ่ อย่างเสาเข็มไอความยาว 10 เมตร จำนวนกว่า 110 ต้น พร้อมวิธีรับมือกับอุปสรรคใต้ผิวน้ำที่หลีกเลี่ยงไม่ได้\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. การบริหารจัดการหน้างาน: ลำเลียงเสาเข็มไอ (Micropile I-Shape) เข้าสู่พื้นที่\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เริ่มต้นเช้าวันทำงาน ทีมงานได้ดำเนินการประสานงานเพื่อขนย้ายเสาเข็มเข้าสู่พื้นที่หน้างานอย่างเป็นระบบ สำหรับโปรเจกต์เขื่อนกันดินนี้ ทางทีมวิศวกรได้ออกแบบและเลือกใช้ <strong>เสาเข็มรูปตัวไอ (I-Shape Concrete Pile)</strong> หรือที่ในวงการช่างมักเรียกกันว่าไมโครไพล์ตัวไอ ซึ่งมีคุณสมบัติโดดเด่นในการรับน้ำหนักและทนทานต่อแรงดันดินด้านข้างได้ดีเยี่ยม\n            </p>\n            \n            <div class=\"row\" style=\"margin-top: 20px;\">\n                <div class=\"col-md-5 text-center\" style=\"margin-bottom: 20px;\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-2.webp\" alt=\"การลำเลียงเสาเข็มไอ I-Shape Micropile ความยาว 10 เมตร สำหรับงานเขื่อนกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>ภาพการเตรียมพร้อมเสาเข็มไอ (I-Shape) รอการกดลงดิน</em></p>\n                </div>\n                <div class=\"col-md-7\">\n                    <h4 style=\"font-weight: bold; color: #333;\">ทำไมต้องใช้เสาเข็มยาวถึง 10 เมตร และใช้มากถึง 110 ต้น?</h4>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        การสร้างกำแพงกันดินริมน้ำ มีความเสี่ยงเรื่องการทรุดตัวและดินสไลด์สูงมาก การใช้เสาเข็มความยาว <strong>10 เมตร</strong> คือการคำนวณเผื่อระยะให้ปลายเข็มหยั่งลึกลงไปทะลุชั้นดินอ่อน (Soft Clay) จนถึงชั้นดินที่มีความหนาแน่นและมีค่าความฝืด (Skin Friction) ที่เหมาะสม ช่วยยึดเกาะโครงสร้างเขื่อนทั้งหมดให้ต้านทานกระแสน้ำได้\n                    </p>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        ส่วนจำนวนเสาเข็มที่มากถึง <strong>110 ต้น</strong> นั้น เป็นการออกแบบระยะห่างระหว่างต้น (Spacing) ให้ถี่เพียงพอที่จะรับน้ำหนักของแผ่นเสียบและแรงดันดินด้านหลังกำแพงได้อย่างสมดุล ไม่เกิดการโก่งตัวในอนาคตครับ\n                    </p>\n                </div>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. อุปสรรคที่คาดการณ์ไว้: การเคลียร์ \"หินทิ้งใต้น้ำ\" ก่อนเริ่มกดเข็ม\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                แม้การเตรียมเสาเข็มจะพร้อมร้อยเปอร์เซ็นต์ แต่ในงานก่อสร้างริมน้ำ มักจะมีอุปสรรคที่ซ่อนอยู่ใต้ผิวน้ำเสมอ นั่นคือ <strong>\"แนวหินทิ้งจากเขื่อนเดิม\"</strong> ซึ่งในอดีตมักจะมีการทิ้งก้อนหินขนาดใหญ่ลงไปเพื่อป้องกันตลิ่งพัง \n            </p>\n            \n            <div class=\"alert alert-warning\" style=\"margin-top: 20px; border-left: 5px solid #d9534f;\">\n                <h4 style=\"color: #d9534f; margin-top: 0;\"><i class=\"fa fa-exclamation-triangle\"></i> ผลกระทบหากไม่เคลียร์หินใต้น้ำ</h4>\n                <p style=\"margin-bottom: 0; line-height: 1.6;\">\n                    หากเราฝืนเดินเครื่อง <a href=\"https://www.theeraphong.com/images/pile\" target=\"_blank\">กดเสาเข็ม (Pile Driving)</a> ลงไปปะทะกับก้อนหินเหล่านี้โดยตรง จะทำให้เกิดปัญหา <strong>\"เสาเข็มหนีศูนย์\"</strong> หรือปลายเสาเข็มแตกหักเสียหาย ซึ่งจะส่งผลร้ายแรงต่อความสามารถในการรับน้ำหนัก (Load Bearing Capacity) ของฐานราก\n                </p>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                <strong>วิธีแก้ปัญหา:</strong> ทางทีมงานได้ปรับแผนหน้างานทันที โดยใช้รถแบคโฮ (แมคโคร) เข้ามาทำการขุด เกลี่ย และงมก้อนหินใต้น้ำในแนวที่จะต้องกดเสาเข็มออกให้หมดก่อน ขั้นตอนนี้ต้องอาศัยความชำนาญของคนขับเครื่องจักรอย่างมาก เพื่อให้แนวดินโล่งและปลอดภัยที่สุดสำหรับเสาเข็มทุกต้น\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. แผนการดำเนินงาน: กดเสาเข็ม 110 ต้น ด้วยเวลา 4-5 วัน\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากเคลียร์แนวหินใต้น้ำสำเร็จ ทีมงานจะเข้าสู่กระบวนการนำรถแบคโฮมากดเสาเข็ม (ใช้ระบบกดไฮดรอลิกจากน้ำหนักรถ แทนการใช้ปั้นจั่นตอก เพื่อลดแรงสั่นสะเทือนไม่ให้กระทบโครงสร้างบ้านข้างเคียง) \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ด้วยประสิทธิภาพของเครื่องจักรและทีมช่างที่คุ้นเคยกับงาน เราได้ประเมินไทม์ไลน์ (Timeline) การทำงานไว้ว่า การกดเสาเข็มความยาว 10 เมตร จำนวน 110 ต้นนี้ จะใช้ระยะเวลาดำเนินการเพียง <strong>4-5 วันทำการ</strong> เท่านั้น ซึ่งถือว่าเป็นความเร็วที่อยู่ในเกณฑ์มาตรฐานสูง ทำให้งานเดินหน้าได้รวดเร็ว ลดผลกระทบเรื่องเสียงรบกวนต่อเพื่อนบ้านให้น้อยที่สุดครับ\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. การบริหารเวลาแบบมืออาชีพ: เตรียมงาน \"หล่อแผ่นเสียบกำแพงกันดิน\" ควบคู่กันไป\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เวลาทุกนาทีในไซต์งานก่อสร้างมีค่า! เพื่อไม่ให้เสียเวลารอคอย ทางทีมงานจึงได้จัดการทำงานแบบคู่ขนาน (Parallel Tasking) โดยในขณะที่เครื่องจักรกำลังจัดการเรื่องการกดเสาเข็มอยู่นั้น อีกมุมหนึ่งของหน้างาน ทีมช่างโครงสร้างได้เริ่มจัดเตรียมพื้นที่และ <strong>\"อุปกรณ์สำหรับหล่อแผ่นเสียบกำแพงกันดิน (Precast Concrete Panels)\"</strong> รอไว้แล้ว\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-7\">\n                    <ul class=\"list-group\" style=\"font-size: 16px;\">\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-primary\" style=\"margin-top: 0; font-weight: bold;\"><i class=\"fa fa-cubes\"></i> การทำพิมพ์หล่อมาตรฐาน</h4>\n                            <p style=\"margin-bottom: 0;\">เราใช้แบบหล่อ (Formwork) ที่ได้มาตรฐาน เพื่อให้แผ่นเสียบทุกแผ่นมีขนาดที่เท่ากันเป๊ะ เมื่อนำไปเสียบลงในร่องของเสาเข็มไอ จะประกบกันสนิท ไม่เกิดช่องโหว่ให้น้ำหรือดินรั่วซึม</p>\n                        </li>\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-primary\" style=\"margin-top: 0; font-weight: bold;\"><i class=\"fa fa-link\"></i> โครงเหล็กคุณภาพสูง (Rebar)</h4>\n                            <p style=\"margin-bottom: 0;\">ภายในแผ่นปูนทุกแผ่น จะถูกผูกด้วยเหล็กเสริมโครงสร้าง (Steel Reinforcement) คุณภาพสูงตามหลักวิศวกรรม เพื่อให้แผ่นเสียบมีความเหนียว รับแรงดัด (Bending Moment) จากแรงดันดินด้านหลังกำแพงได้อย่างมีประสิทธิภาพ</p>\n                        </li>\n                    </ul>\n                </div>\n                <div class=\"col-md-5 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-3.webp\" alt=\"เตรียมโครงเหล็กและพิมพ์หล่อแผ่นเสียบกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>พิมพ์หล่อแผ่นเสียบ และโครงเหล็กที่เตรียมไว้รอการเทปูน</em></p>\n                </div>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px; margin-top: 20px;\">\n                เมื่อการกดเสาเข็มทั้ง 110 ต้นเสร็จสิ้นลง แผ่นเสียบเหล่านี้ก็จะถูกบ่มจนได้ค่าความแข็งแรง (Strength) ที่พอดี พร้อมนำมาประกอบเป็นกำแพงกันดินได้ทันทีครับ นี่คือวิธีการทำงานที่ช่วยให้เจ้าของบ้านได้งานที่รวดเร็วและเต็มเปี่ยมไปด้วยคุณภาพ\n            </p>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 40px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> ถาม-ตอบ (FAQ) ความรู้เรื่องงานเขื่อนกันดิน</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: การกดเสาเข็มด้วยรถแบคโฮ ดีกว่าการตอกด้วยปั้นจั่นอย่างไร?</h4>\n                <p style=\"margin-bottom: 20px;\">A: การกดเข็มด้วยน้ำหนักของรถแบคโฮ จะก่อให้เกิด <strong>\"แรงสั่นสะเทือนที่ต่ำมาก\" (Low Vibration)</strong> เหมาะสำหรับการทำงานในพื้นที่ชุมชน หรือบ้านริมน้ำที่มีโครงสร้างเก่าอยู่ใกล้เคียง ช่วยลดความเสี่ยงที่บ้านเพื่อนบ้านจะเกิดรอยร้าวครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: ทำไมต้องหล่อแผ่นเสียบที่หน้างาน แทนที่จะซื้อสำเร็จรูป?</h4>\n                <p>A: ในบางพื้นที่ (เช่น ซอยแคบ หรือริมคลอง) การนำรถบรรทุกขนาดใหญ่เข้ามาส่งแผ่นปูนสำเร็จรูปทำได้ยาก การหล่อแผ่นเสียบที่หน้างาน (On-site Casting) จึงช่วยแก้ปัญหาเรื่องการขนส่ง และยังทำให้เราควบคุมคุณภาพของการผูกเหล็กและส่วนผสมคอนกรีตได้ 100% ครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-left: 6px solid #0056b3; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #0056b3;\">สร้างรากฐานที่มั่นคง เพื่อปกป้องทรัพย์สินของคุณ</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    งานเขื่อนและกำแพงกันดินริมน้ำ ไม่ใช่งานที่ใครก็ทำได้ ต้องอาศัยทีมงานที่เข้าใจเรื่องโครงสร้างดิน การรับน้ำหนัก และมีประสบการณ์ในการแก้ปัญหาเฉพาะหน้า <br><br>\n                    หากท่านกำลังประสบปัญหาตลิ่งพัง ดินสไลด์ หรือต้องการสร้างกำแพงกันดินที่แข็งแกร่งทนทาน <strong>ธีรพงษ์เซอร์วิส</strong> ยินดีให้คำปรึกษาและประเมินราคาหน้างานฟรี!\n                </p>\n                <div class=\"row\">\n                    <div class=\"col-sm-6 text-right\">\n                        <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-primary btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px;\">\n                            <i class=\"fa fa-shield\"></i> บริการรับทำกำแพงกันดิน\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6 text-left\">\n                        <a href=\"https://www.theeraphong.com/images/pile\" class=\"btn btn-info btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px;\">\n                            <i class=\"fa fa-cogs\"></i> ดูผลงานกดเสาเข็มของเรา\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1712045863923793.webp', 10, 'กำแพงกันดิน-ซอยบางกร่าง45-5-EP2', '2021-09-27 09:16:08', '2021-09-28 07:18:11'),
(26, 'ขุดบ่อน้ำ ปากน้ำกระโจมทอง', 'งานขุดบ่อน้ำ สถานที่ ที่ปากน้ำกระโจมทอง', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    รีวิวเจาะลึก: งานขุดบ่อน้ำ สระเก็บน้ำการเกษตร (ขนาด 7 x 20 x 2.5 เมตร) เปลี่ยนที่ดินรกร้างให้เกิดมูลค่า\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตผลงานหน้างานล่าสุด | <i class=\"fa fa-leaf\"></i> หมวดหมู่: งานขุดบ่อดิน, ปรับภูมิทัศน์ และ โคกหนองนา\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #f8fcf8; padding: 25px; border-left: 5px solid #5cb85c; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    การจัดการแหล่งน้ำคือหัวใจสำคัญของการพัฒนาที่ดิน ไม่ว่าจะเป็นการทำเกษตรกรรม การทำ <strong>\"โคกหนองนาโมเดล\"</strong> หรือการปรับภูมิทัศน์จัดสวน วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ขอพาทุกท่านมาชมรีวิวผลงาน <strong>การขุดบ่อน้ำบนพื้นที่ดินเปล่า</strong> พร้อมเจาะลึกเทคนิคการทำงาน การคำนวณปริมาตรดิน และการทำสโลป (Slope) เพื่อป้องกันตลิ่งพัง เพื่อเป็นแนวทางสำหรับท่านที่กำลังวางแผนขุดสระเก็บน้ำครับ\n                </p>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. สำรวจหน้างาน: จากที่ดินเปล่า สู่โปรเจกต์ขุดสระเก็บน้ำ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เริ่มต้นโปรเจกต์นี้ ทีมงานได้รับการติดต่อจากลูกค้าที่ต้องการพัฒนาที่ดินเปล่าซึ่งมีลักษณะเป็นพื้นที่ราบรกร้าง ให้กลายเป็นแหล่งกักเก็บน้ำสำหรับการใช้งานในพื้นที่ โดยโจทย์ที่ได้รับมอบหมายคือการขุดบ่อน้ำขนาดมาตรฐาน ที่สามารถกักเก็บน้ำได้เพียงพอตลอดทั้งปี และต้องมีความปลอดภัย ไม่เกิดปัญหาดินสไลด์ในภายหลัง\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/270921/garden-2.webp\" alt=\"สภาพที่ดินเปล่าก่อนเริ่มงานขุดบ่อน้ำ ขุดสระ\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: สภาพหน้างานก่อนเริ่มดำเนินการ เป็นที่ดินเปล่าที่ต้องทำการเคลียร์ริ่ง (Clearing) ก่อนนำเครื่องจักรเข้าพื้นที่</em></p>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. การออกแบบและคำนวณปริมาตรดิน (Earthwork Calculation)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                งานขุดบ่อดินไม่ใช่แค่การนำรถแบคโฮมาตักดินออกไปแล้วจบครับ แต่ต้องผ่านการคำนวณทางวิศวกรรมเพื่อให้ได้สัดส่วนที่ถูกต้อง สำหรับโปรเจกต์นี้ สเปกบ่อน้ำที่ลูกค้าต้องการคือ:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-6\">\n                    <ul class=\"list-group\" style=\"font-size: 16px;\">\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-success\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-arrows-h\"></i> ความกว้าง: 7 เมตร</h4>\n                            <p style=\"margin-bottom: 0;\">เป็นระยะที่เหมาะสม ไม่กว้างจนกินพื้นที่ใช้สอยส่วนอื่น และไม่แคบจนแสงแดดส่องไม่ถึงก้นบ่อ</p>\n                        </li>\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-success\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-arrows-v\"></i> ความยาว: 20 เมตร</h4>\n                            <p style=\"margin-bottom: 0;\">ความยาวระดับนี้ช่วยให้บ่อมีลักษณะเป็นสี่เหลี่ยมผืนผ้า รับปริมาณน้ำฝนได้ดี และง่ายต่อการปรับภูมิทัศน์ริมขอบบ่อ</p>\n                        </li>\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-success\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-level-down\"></i> ความลึก: 2.50 เมตร</h4>\n                            <p style=\"margin-bottom: 0;\">ความลึกระดับ 2.5 เมตร ถือเป็นความลึกมาตรฐานที่แสงแดดสามารถส่องทะลุถึง ช่วยให้ระบบนิเวศใต้น้ำสมดุล และลดการระเหยของน้ำในช่วงฤดูแล้ง</p>\n                        </li>\n                    </ul>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-default\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold; color: #333;\"><i class=\"fa fa-calculator\"></i> เคล็ดลับจากช่าง: ปริมาตรดินที่ถูกขุดขึ้นมา</h4></div>\n                        <div class=\"panel-body\">\n                            <p style=\"line-height: 1.6;\">\n                                หากคำนวณปริมาตรทรงสี่เหลี่ยมเบื้องต้น (กว้าง x ยาว x ลึก) บ่อนี้จะมีปริมาตรดินที่ต้องขุดออกประมาณ <strong>350 ลูกบาศก์เมตร (คิว)</strong> \n                            </p>\n                            <p style=\"line-height: 1.6; margin-bottom: 0;\">\n                                <strong>คำถามคือ ดินเหล่านี้เอาไปไหน?</strong><br>\n                                ลูกค้าสามารถเลือกได้ว่า จะให้ทางเรานำดินไปทิ้ง (มีค่าขนทิ้ง) หรือจะนำดินที่ขุดได้นี้ ไปทำ <strong>\"คันล้อม\"</strong> รอบบ่อ หรือปั้นเป็น <strong>\"โคก\"</strong> สำหรับปลูกต้นไม้และสร้างบ้านพักตามหลักโคกหนองนาโมเดล ซึ่งวิธีหลังนี้จะช่วยประหยัดงบประมาณและเกิดประโยชน์สูงสุดครับ!\n                            </p>\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ปฏิบัติการหน้างาน: การขุดและแต่งสโลป (Slope) ป้องกันตลิ่งพัง\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เมื่อแผนงานชัดเจน ทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> ได้นำรถแบคโฮ (แมคโคร) ขนาดที่เหมาะสมเข้าสู่พื้นที่ สิ่งสำคัญที่สุดในการขุดบ่อดินลึก 2.5 เมตร คือ <strong>\"การทำสโลป (Slope) หรือความลาดเอียงของขอบบ่อ\"</strong>\n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หากเราขุดขอบบ่อเป็นแนวตั้งฉาก 90 องศา เมื่อถึงฤดูฝน ดินอุ้มน้ำจะเกิดการสไลด์และพังทลายลงไปอุดก้นบ่ออย่างแน่นอน ทีมพนักงานขับเครื่องจักรของเรามีความชำนาญในการ \"แต่งตลิ่ง\" ให้มีความลาดเอียงในสัดส่วน 1:1 หรือ 1:1.5 (ขึ้นอยู่กับสภาพดิน) เพื่อให้ดินพยุงตัวมันเองได้อย่างมั่นคง\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/270921/garden-1.webp\" alt=\"ผลงานการขุดบ่อน้ำ สระเก็บน้ำ ขนาด 7x20x2.5 เมตร โดยธีรพงษ์เซอร์วิส\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2: ผลงานขุดบ่อน้ำเสร็จสมบูรณ์ สังเกตการแต่งขอบสโลปที่สวยงาม ได้มาตรฐาน พร้อมกักเก็บน้ำทันที</em></p>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. ส่งมอบงานตรงเวลา ด้วยคุณภาพที่คุณวางใจ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                งานขุดบ่อน้ำโปรเจกต์นี้สำเร็จลุล่วงไปได้ด้วยดีตามระยะเวลาที่กำหนดไว้ ทรงบ่อสวยงาม ได้ความกว้าง ความยาว และความลึกตรงตามสเปกที่ตกลงไว้ในสัญญาเป๊ะ ทางทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> ต้องขอขอบพระคุณลูกค้าเป็นอย่างสูง ที่ให้ความไว้วางใจเลือกใช้บริการเครื่องจักรและทีมช่างของเราครับ\n            </p>\n\n            <div style=\"background-color: #f4f8fa; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #bce8f1;\">\n                <h3 style=\"color: #31708f; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> คำถามที่พบบ่อย (FAQ) เกี่ยวกับงานขุดบ่อน้ำ</h3>\n                <hr style=\"border-color: #9acfea;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: ขุดสระ 1 งาน หรือขุดบ่อเลี้ยงปลา ราคาประเมินจากอะไร?</h4>\n                <p style=\"margin-bottom: 20px;\">A: ราคาค่ารับเหมาขุดสระ จะประเมินจาก 1) ปริมาตรดินที่ขุด (กว้างxยาวxลึก) 2) การจัดการดิน (นำไปทิ้งภายนอก หรือเกลี่ยในพื้นที่) และ 3) สภาพหน้างาน (รถแบคโฮและรถดัมพ์สามารถเข้าออกได้สะดวกหรือไม่) โดยทางเรามีบริการประเมินราคาฟรีครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: ควรขุดบ่อลึกกี่เมตรดี น้ำถึงจะไม่แห้ง?</h4>\n                <p style=\"margin-bottom: 20px;\">A: ตามมาตรฐานทั่วไปแนะนำให้ขุดลึกตั้งแต่ 3-4 เมตรขึ้นไป (หากสภาพดินอำนวย) เพื่อให้ก้นบ่อทะลุไปถึงตาน้ำใต้ดิน และมีความลึกพอที่จะชดเชยน้ำที่ระเหยไปในช่วงฤดูร้อนแดดจัดครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: ขุดบ่อน้ำในที่ดินตัวเอง ต้องขออนุญาตหรือไม่?</h4>\n                <p>A: หากขุดบ่อที่มีความลึกจากระดับพื้นดินเกิน 3 เมตร หรือมีพื้นที่ปากบ่อเกิน 10,000 ตารางเมตร (ตาม พ.ร.บ. การขุดดินและถมดิน) จะต้องทำการแจ้งและขออนุญาตต่อเจ้าพนักงานท้องถิ่นครับ ซึ่งทางทีมงานเราพร้อมให้คำแนะนำในส่วนนี้</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #5cb85c; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">รับเหมาขุดบ่อ ขุดสระ โคกหนองนา ครบวงจร</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    เปลี่ยนที่ดินรกร้าง ให้กลายเป็นแหล่งกักเก็บน้ำเพื่อการเกษตร หรือจัดสวนปรับภูมิทัศน์ <br>ด้วยเครื่องจักรมาตรฐานและทีมงานมืออาชีพที่ไม่ทิ้งงาน\n                </p>\n                \n                <a href=\"https://www.theeraphong.com/garden-plot\" class=\"btn btn-success btn-lg\" style=\"padding: 15px 40px; font-weight: bold; border-radius: 30px; font-size: 18px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                    <i class=\"fa fa-leaf\"></i> ดูผลงานขุดบ่อดิน และงานจัดสวน เพิ่มเติม\n                </a>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1712046972067174.webp', 11, 'ขุดบ่อน้ำ-ปากน้ำกระโจมทอง', '2021-09-27 09:33:45', '2021-09-27 09:33:45');
INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(27, 'กำแพง กันดิน ซอยไทรม้า 19', 'ส่งงานก่อสร้างกำแพง กันดินซอยไทรม้ 19', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    เจาะลึกโครงสร้าง: กำแพงกันดินเสริมสเตย์ (Stay Beam) คืออะไร? พร้อมวิธีประเมินราคาและขั้นตอนการสร้างจริง\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตผลงานหน้างาน ซอยไทรม้า | <i class=\"fa fa-folder-open\"></i> หมวดหมู่: ความรู้งานฐานราก, เขื่อนกันดิน\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #f4f8fa; padding: 25px; border-left: 5px solid #0056b3; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 10px;\"><strong>คำถามที่คนทำบ้านริมน้ำหรือที่ดินถมสูงสงสัยมากที่สุด:</strong></p>\n                <ul style=\"margin-bottom: 0;\">\n                    <li><em>\"ทำกำแพงกันดินเสริมสเตย์ ราคาเมตรละเท่าไหร่?\"</em></li>\n                    <li><em>\"กำแพงกันดินแบบมีสเตย์ แตกต่างจากกำแพงกันดินทั่วไปอย่างไร?\"</em></li>\n                    <li><em>\"ขั้นตอนการก่อสร้างที่ถูกต้องและได้มาตรฐาน มีวิธีอย่างไร?\"</em></li>\n                </ul>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ได้ดำเนินการส่งมอบงานก่อสร้าง <strong>กำแพงกันดินแบบเสริมสเตย์ (Retaining Wall with Stay Beam)</strong> ณ หน้างานซอยไทรม้า เสร็จสิ้นอย่างสมบูรณ์ เราจึงขอใช้โอกาสนี้นำเสนอและเจาะลึกถึงเบื้องหลังการทำงาน เผยทุกขั้นตอนการก่อสร้างที่ได้มาตรฐาน เพื่อเป็นวิทยาทานและข้อมูลประกอบการตัดสินใจสำหรับท่านที่กำลังวางแผนทำเขื่อนหรือกำแพงกันดินครับ\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/271021/271021-5.webp\" alt=\"ภาพมุมสูง โครงสร้างกำแพงกันดินเสริมสเตย์ ซอยไทรม้า\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 6px 15px rgba(0,0,0,0.15);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพมุมสูง: โครงสร้างกำแพงกันดินริมคลองที่สร้างเสร็จสมบูรณ์ แข็งแกร่งด้วยระบบคานดึงรั้ง (สเตย์)</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. ทำไมราคากำแพงกันดินถึงแตกต่างกัน? (ปัจจัยที่ใช้ประเมินราคา)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลายท่านมักจะสอบถามราคาประเมินเบื้องต้น แต่ในความเป็นจริง การตีราคางานกำแพงกันดินไม่สามารถระบุตายตัวเป็น \"ราคาต่อเมตร\" ได้ในทันที ผู้รับเหมามืออาชีพจะต้องลงพื้นที่ประเมินหน้างานอย่างละเอียด โดยพิจารณาจาก 3 อุปสรรคหลัก ซึ่งในโปรเจกต์ซอยไทรม้าแห่งนี้ เราต้องเผชิญและก้าวผ่านความท้าทายเหล่านี้มาได้สำเร็จครับ:\n            </p>\n            \n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-7\">\n                    <h4 style=\"font-weight: bold; color: #d9534f;\">อุปสรรคที่ 1: แนวหินแข็งใต้น้ำ (Underwater Rocks)</h4>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        การทำงานริมน้ำมักเจอเศษวัสดุหรือหินที่ถูกทิ้งไว้ในอดีต หินเหล่านี้คืออุปสรรคชิ้นใหญ่ในการกดเสาเข็มไมโครไพล์ (Micropile) หากฝืนกดลงไป เข็มอาจแตกหักหรือหนีศูนย์ได้ \n                    </p>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        <strong>การแก้ปัญหา:</strong> ทีมงานต้องใช้รถแบคโฮ (แมคโคร) ติดตั้งหัวขุด ลงไปทำการเคลียร์เศษหินและงมวัสดุใต้น้ำออก \"ทุกจุด\" ที่เป็นตำแหน่งลงเสาเข็ม ซึ่งขั้นตอนนี้ต้องใช้ความระมัดระวังสูงและทำให้งบประมาณหรือระยะเวลาดำเนินการเพิ่มขึ้นจากงานบนดินปกติ\n                    </p>\n                </div>\n                <div class=\"col-md-5 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/180921/180921-1.webp\" alt=\"เศษหินใต้น้ำ อุปสรรคในการกดเสาเข็มกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-height: 400px; object-fit: cover; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>เศษหินและอุปสรรคใต้น้ำที่ต้องเคลียร์ก่อนกดเข็ม</em></p>\n                </div>\n            </div>\n\n            <div class=\"row\" style=\"margin-top: 40px;\">\n                <div class=\"col-md-5 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/1711139361714176.webp\" alt=\"รถแบคโฮเดินบนแผ่นเหล็กบนดินถมใหม่\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>การใช้แผ่นเหล็กปูทางเดินรถเครื่องจักรหนักบนดินอ่อน</em></p>\n                </div>\n                <div class=\"col-md-7\">\n                    <h4 style=\"font-weight: bold; color: #d9534f;\">อุปสรรคที่ 2: สภาพดินถมใหม่ที่ยังไม่เซ็ตตัว (Uncompacted Soil)</h4>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        พื้นที่หน้างานมีลักษณะเป็นดินที่เพิ่งถูกถมเข้ามาใหม่ และยังไม่ผ่านการบดอัด (Compaction) ทำให้ดินมีความร่วนซุยและรับน้ำหนักไม่ได้ รถเครื่องจักรหนักอย่างแบคโฮไม่สามารถขับเข้าไปทำงานได้โดยตรง เพราะเสี่ยงต่อการจมและเกิดอุบัติเหตุ\n                    </p>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        <strong>การแก้ปัญหา:</strong> เราต้องบริหารจัดการหน้างานโดยการเช่า <strong>\"แผ่นเหล็กปูทาง (Steel Plates)\"</strong> มาปูเป็นเส้นทางเดินรถ เพื่อกระจายน้ำหนักของเครื่องจักรให้ปลอดภัยที่สุด (สำหรับท่านที่สนใจรายละเอียดและราคาเกี่ยวกับการถมดิน สามารถอ่านเพิ่มเติมได้ <a href=\"https://www.theeraphong.com/landfill\" target=\"_blank\"><strong>ที่นี่</strong></a> ครับ)\n                    </p>\n                </div>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px; margin-top: 25px;\">\n                <strong style=\"color: #d9534f;\">อุปสรรคที่ 3: สภาพอากาศ (Weather Conditions)</strong> <br>\n                ปัจจัยที่ไม่สามารถควบคุมได้อย่างพายุ ลม ฝน หรือระดับน้ำหลาก ล้วนส่งผลกระทบให้หน้างานต้องหยุดชะงัก ผู้รับเหมาจึงต้องมีความเชี่ยวชาญในการเผื่อเวลาและวางแผนสำรอง (Risk Management) ไว้ในใบเสนอราคาเสมอ\n            </p>\n\n\n            <h2 style=\"color: #0056b3; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. เจาะลึกขั้นตอน: วิธีสร้างกำแพงกันดินเสริมสเตย์ที่ได้มาตรฐาน\n            </h2>\n            \n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/271021/271021-1.webp\" alt=\"แบบแปลนโครงสร้างกำแพงกันดินและเสาเข็มสเตย์\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 700px; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>แบบแปลน (Blueprint) แสดงโครงสร้างการเชื่อมต่อระหว่างเสาเข็มหลักและเสาเข็มสเตย์</em></p>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                โครงสร้างกำแพงกันดินที่ดี ไม่ใช่แค่การปักเสาลงไปแล้วจบ แต่คือการทำงานประสานกันของรากฐานหลายระบบ ดังนี้ครับ:\n            </p>\n\n            <ul class=\"list-group\" style=\"font-size: 16px; margin-top: 20px;\">\n                \n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">ขั้นตอนที่ 1: การกดเสาเข็มหลัก (Main Pile) รับแนวกำแพง</h4>\n                    <p style=\"line-height: 1.6; margin-bottom: 15px;\">เริ่มจากการกดเสาเข็มหลักเพื่อกำหนดแนวกำแพง และเตรียมร่องสำหรับใส่แผ่นเสียบกันดิน เสาเข็มกลุ่มนี้จะทำหน้าที่รับน้ำหนักตัวกำแพงและต้านทานแรงดันดินด้านข้าง (Lateral Earth Pressure) ในระดับแรก</p>\n                    <div class=\"well well-sm\" style=\"background-color: #fcf8e3; border-color: #faebcc; color: #8a6d3b;\">\n                        <strong>สเปกวัสดุ:</strong> โปรเจกต์นี้เราเลือกใช้ <strong>เสาเข็มไมโครไพล์ (Micropile) รูปตัวไอ (I-Shape) ขนาด 18 เซนติเมตร ความยาว 10 เมตร</strong> โดยกดฝังลึกลงไปในดินประมาณ 8-9 เมตร เพื่อให้ปลายเข็มทะลุชั้นดินอ่อนไปยึดเกาะกับชั้นดินเหนียวแข็ง\n                    </div>\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/271021/271021-7.webp\" alt=\"ด้านหน้าแนวกำแพงกันดินหลัก\" class=\"img-responsive img-rounded\" style=\"margin-top: 15px; max-height: 300px;\">\n                </li>\n\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">ขั้นตอนที่ 2: การกดเสาเข็มสเตย์ (Stay Pile) หัวใจของความมั่นคง</h4>\n                    <p style=\"line-height: 1.6; margin-bottom: 15px;\">นี่คือจุดชี้เป็นชี้ตายของกำแพง! <strong>\"สเตย์\"</strong> คือระบบดึงรั้ง หากกำแพงกันดินริมคลองหรือที่ดินถมสูงไม่มีสเตย์ โอกาสที่กำแพงจะแบะล้มลงน้ำมีสูงถึง 90%</p>\n                    <p style=\"line-height: 1.6; margin-bottom: 15px;\">เราดำเนินการกดเสาเข็มสเตย์ (Micropile I-18 ยาว 10 เมตร กดลึก 9 เมตรเช่นกัน) โดยถอยร่นระยะเข้ามาบนฝั่ง <strong>ห่างจากแนวเสาเข็มหลักประมาณ 1.50 เมตร</strong> ทำหน้าที่เสมือน \"สมอเรือ\" ที่คอยดึงรั้งกำแพงหน้าไม่ให้ล้ม</p>\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/271021/271021-3.webp\" alt=\"แนวเสาเข็มสเตย์ดึงรั้งกำแพง\" class=\"img-responsive img-rounded\" style=\"margin-top: 15px; max-height: 300px;\">\n                </li>\n\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">ขั้นตอนที่ 3-4: งานประกอบแผ่นเสียบและเทคานเชื่อม (Monolithic Casting)</h4>\n                    <p style=\"line-height: 1.6; margin-bottom: 10px;\">เมื่อฐานรากมั่นคงแล้ว เราจะดำเนินการ <strong>เสียบแผ่นพื้นคอนกรีต</strong> ลงไปตามร่องของเสาเข็มไอหลักเพื่อปิดกั้นดิน</p>\n                    <p style=\"line-height: 1.6; margin-bottom: 0;\">จากนั้นจึงเข้าสู่ขั้นตอนสำคัญ คือการ <strong>ผูกเหล็กและเทคอนกรีตคานทับหลัง (คานบน) พร้อมกับคานสเตย์ให้ประสานเข้าด้วยกันแบบไร้รอยต่อ (Monolithic)</strong> ทำให้เสาเข็มหน้า เข็มสเตย์ และแผ่นเสียบ กลายเป็นโครงสร้างเดียวกันที่แข็งแกร่งดุจหินผา</p>\n                </li>\n            </ul>\n\n            <h2 style=\"color: #0056b3; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ต่อยอดฟังก์ชัน: การสร้างกำแพงรั้วบนคานเขื่อนกันดิน\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                นอกจากโครงสร้างใต้ดินที่แข็งแรงแล้ว <strong>คุณบ๊อบบี้</strong> (ลูกค้าคนสำคัญของเราในโปรเจกต์นี้) ยังได้มอบความไว้วางใจให้ทีมงานธีรพงษ์เซอร์วิส ดำเนินการออกแบบและก่อสร้าง \"รั้วด้านบนสันกำแพงกันดิน\" ต่อเนื่องไปเลย เพื่อให้ตอบโจทย์การใช้งานจริงในแต่ละโซนของบ้าน โดยแบ่งออกเป็น 3 รูปแบบหลักๆ คือ:\n            </p>\n            \n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-5 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/271021/271021-6.webp\" alt=\"กำแพงแบบทึบ สร้างบนฐานกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>รั้วกำแพงแบบทึบ ก่ออิฐฉาบปูนบนสันกำแพงกันดิน</em></p>\n                </div>\n                <div class=\"col-md-7\">\n                    <ol style=\"font-size: 16px; line-height: 1.8; margin-top: 15px;\">\n                        <li style=\"margin-bottom: 15px;\"><strong>รั้วกำแพงแบบทึบ (Solid Fence):</strong> ก่ออิฐฉาบปูนปิดทึบ เหมาะสำหรับโซนที่ต้องการเพิ่มความเป็นส่วนตัวสูงสุด บังสายตาจากภายนอก และกันฝุ่นลม</li>\n                        <li style=\"margin-bottom: 15px;\"><strong>รั้วกำแพงเหล็ก (Steel Fence):</strong> ผสมผสานโครงเหล็กซี่โปร่ง ช่วยให้อากาศถ่ายเทได้ดี ลมพัดผ่านได้สบาย และเพิ่มความสวยงามโมเดิร์นให้กับตัวบ้าน</li>\n                        <li style=\"margin-bottom: 15px;\"><strong>รั้วกำแพงแบบเตี้ย (Low Wall):</strong> ออกแบบมาเพื่อโซนที่ติดริมแม่น้ำหรือริมคลองโดยเฉพาะ เพื่อให้เจ้าของบ้านสามารถนั่งพักผ่อนและชมทัศนียภาพริมน้ำได้โดยไม่ถูกบดบังสายตา</li>\n                    </ol>\n                    <div class=\"alert alert-success\" style=\"margin-top: 20px;\">\n                        <i class=\"fa fa-check-circle\"></i> <strong>มั่นใจได้ 100%:</strong> ด้วยรากฐานของเสาเข็มคู่ (หลัก+สเตย์) ที่กดลึกลงไปถึง 9 เมตร การรับน้ำหนักของรั้วด้านบนทั้ง 3 แบบนี้ จึงเป็นเรื่องง่ายดาย โครงสร้างนี้สามารถตั้งตระหง่านอยู่คู่บ้านคุณไปได้ยาวนานเป็นหลายสิบ หรือหลายร้อยปีอย่างแน่นอนครับ!\n                    </div>\n                </div>\n            </div>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> คำถามที่พบบ่อย (FAQ) เกี่ยวกับกำแพงกันดินสเตย์</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: ไม่ทำสเตย์ได้ไหม? เพื่อประหยัดงบประมาณ</h4>\n                <p style=\"margin-bottom: 20px;\">A: <strong style=\"color: #d9534f;\">ไม่แนะนำอย่างยิ่งครับ</strong> โดยเฉพาะพื้นที่ติดคลอง หรือพื้นที่ที่มีการถมดินสูงกว่าเพื่อนบ้านเกิน 1 เมตร หากไม่มีคานสเตย์ช่วยดึงรั้งไว้ แรงดันจากน้ำหนักดินและน้ำฝนจะดันให้กำแพงหลักหักหรือโค่นล้มในที่สุด เสียน้อยเสียยาก เสียมากเสียง่ายครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: การทำกำแพงกันดิน ใช้เวลาดำเนินการนานแค่ไหน?</h4>\n                <p>A: ขึ้นอยู่กับความยาวของหน้างานและอุปสรรคใต้ดินครับ แต่โดยทั่วไปสำหรับหน้างานความยาว 20-30 เมตร หากไม่มีอุปสรรคหินใต้น้ำ จะใช้เวลาดำเนินการตั้งแต่เริ่มกดเข็มจนถึงเทคานแล้วเสร็จ ประมาณ 15-20 วันทำการครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-left: 6px solid #0056b3; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #0056b3; font-weight: bold;\">วางรากฐานบ้านคุณ ให้มั่นคงอย่างมืออาชีพ</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    การก่อสร้างกำแพงกันดินคืองานวิศวกรรมที่ละเอียดอ่อน ต้องอาศัยประสบการณ์และความซื่อสัตย์ในการใช้วัสดุ <br>ทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> พร้อมเป็นที่ปรึกษาและดำเนินการแก้ปัญหาหน้างานให้ท่านอย่างตรงไปตรงมา\n                </p>\n                \n                <div style=\"font-size: 24px; color: #c9302c; font-weight: bold; margin-bottom: 20px;\">\n                    <i class=\"fa fa-phone-square\"></i> ปรึกษาและประเมินราคาฟรี โทร: 062-718-8847\n                </div>\n\n                <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-primary btn-lg\" style=\"padding: 15px 40px; font-weight: bold; border-radius: 30px; font-size: 18px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                    <i class=\"fa fa-info-circle\"></i> ดูรายละเอียดและผลงาน กำแพงกันดิน เพิ่มเติม\n                </a>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1714793341402425.webp', 10, 'กำแพงกันดิน-ซอยไทรม้า19-ส่งงาน', '2021-10-27 17:06:07', '2021-10-27 17:13:27'),
(28, 'เทพื้นปูน ราคาต่อ ตาราง เมตร 2567 | รับเหมาเทพื้นคอนกรีต มืออาชีพ', 'เช็คราคาการเทพื้นปูนล่าสุดปี 2567 พร้อมข้อมูลเทพื้นคอนกรีต พื้นปูนขัดมัน ราคาค่าแรง ตารางเมตรละเท่าไหร่ บริการเทพื้นคุณภาพ ติดต่อทีมงานมืออาชีพได้ที่นี่', '<h2>💰 ราคาการเทพื้นปูนต่อ ตารางเมตร ปี 2567</h2><p>ราคาการเทพื้นปูนในปี 2567 มีความหลากหลายขึ้นอยู่กับความหนาของพื้นและประเภทของคอนกรีตที่ใช้ โดยทั่วไป ราคาจะอยู่ในช่วงดังนี้:</p><h3>🔹 ความหนา 10 ซม.</h3><ul><li><p>คอนกรีต 180 ksc: ประมาณ 390–420 บาท/ตร.ม.</p></li><li><p>คอนกรีต 210 ksc: ประมาณ 410–430 บาท/ตร.ม.</p></li><li><p>คอนกรีต 240 ksc: ประมาณ 440–460 บาท/ตร.ม.</p></li></ul><h3>🔹 ความหนา 15 ซม.</h3><ul><li><p>คอนกรีต 180 ksc: ประมาณ 490–520 บาท/ตร.ม.</p></li><li><p>คอนกรีต 210 ksc: ประมาณ 510–530 บาท/ตร.ม.</p></li><li><p>คอนกรีต 240 ksc: ประมาณ 540–560 บาท/ตร.ม.</p></li></ul><h3>🔹 ความหนา 20 ซม.</h3><ul><li><p>คอนกรีต 180 ksc: ประมาณ 790–820 บาท/ตร.ม.</p></li><li><p>คอนกรีต 210 ksc: ประมาณ 850–860 บาท/ตร.ม.</p></li></ul><p>คอนกรีต 240 ksc: ประมาณ 890–900 บาท/ตร.ม.</p><p>ราคาดังกล่าวเป็นราคาประมาณการและอาจเปลี่ยนแปลงได้ตามปัจจัยต่าง ๆ เช่น พื้นที่ที่ต้องการเทพื้น ความยากง่ายของงาน และต้นทุนวัสดุในแต่ละพื้นที่</p><hr><h2>🏡 ประเภทของพื้นปูนและการใช้งาน</h2><h3>✅ พื้นปูนขัดมัน</h3><p>พื้นปูนขัดมันเป็นที่นิยมในงานตกแต่งภายในและภายนอก เนื่องจากมีความเรียบเนียนและดูทันสมัย ราคาการเทพื้นปูนขัดมันอยู่ที่ประมาณ 450–500 บาท/ตร.ม. </p><img src=\"https://minio.speedynetloans.net/theeraphong/images/services/51ed6b20-f477-458d-a61d-411010457881.webp\"><h3>✅ <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://www.theeraphong.com/pour-concrete\">พื้นคอนกรีตเสริมเหล็ก</a></h3><p>เหมาะสำหรับพื้นที่ที่ต้องรับน้ำหนักมาก เช่น โรงงานหรือโรงจอดรถ ราคาจะสูงขึ้นตามความหนาและประเภทของเหล็กที่ใช้เสริม</p><hr><h2>📌 ปัจจัยที่มีผลต่อราคาการเทพื้นปูน</h2><ol><li><p><strong>ความหนาของพื้น</strong>: ยิ่งพื้นหนา ราคาจะยิ่งสูงขึ้นเนื่องจากต้องใช้วัสดุมากขึ้น</p></li><li><p><strong>ประเภทของคอนกรีต</strong>: คอนกรีตที่มีความแข็งแรงสูงจะมีราคาสูงกว่า</p></li><li><p><strong>พื้นที่ที่ต้องการเทพื้น</strong>: พื้นที่ขนาดใหญ่สามารถต่อรองราคาได้มากกว่าพื้นที่ขนาดเล็ก</p></li><li><p><strong>ความยากง่ายของงาน</strong>: พื้นที่ที่เข้าถึงยากหรือมีรูปทรงซับซ้อนจะมีค่าแรงสูงขึ้น</p></li></ol><hr><h2>📞 ติดต่อบริการเทพื้นปูนมืออาชีพ</h2><p>หากคุณกำลังมองหาผู้รับเหมาเทพื้นปูนที่มีประสบการณ์และเชื่อถือได้ สามารถติดต่อเราได้ที่:</p><ul><li><p><strong>โทรศัพท์</strong>: <strong>062-718-8847</strong></p></li><li><p><strong>LINE ID</strong>: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://line.me/ti/p/h9SHumuTEB\"><strong>0627188847</strong></a></p></li><li><p><strong>อีเมล</strong>: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"mailto:theeraphong.services@gmail.com\"><strong>theeraphong.services@gmail.com</strong></a></p></li></ul><p>เรามีทีมงานมืออาชีพพร้อมให้บริการคุณในทุกขั้นตอนของการเทพื้นปูน ตั้งแต่การวางแผนจนถึงการส่งมอบงาน</p><hr><h2>📝 สรุป</h2><p>การเทพื้นปูนเป็นงานที่ต้องการความชำนาญและการวางแผนที่ดี เพื่อให้ได้พื้นผิวที่มีคุณภาพและทนทานต่อการใช้งาน การเลือกใช้บริการจากผู้รับเหมาที่มีประสบการณ์จะช่วยให้คุณมั่นใจในคุณภาพของงานและความคุ้มค่าของงบประมาณ</p><p>หากคุณต้องการข้อมูลเพิ่มเติมหรือคำปรึกษาเกี่ยวกับการเทพื้นปูน สามารถติดต่อเราได้ตามข้อมูลที่ระบุไว้ข้างต้น เรายินดีให้บริการคุณด้วยความมืออาชีพและใส่ใจในทุกรายละเอียดของงาน</p>', 'images/services/6e825854-deb8-43c4-a02a-24e2dc9dab1f.webp', 27, 'เทพื้นปูน-ราคาต่อตารางเมตร-2567-รับเหมาเทพื้นคอนกรีต-มืออาชีพ', '2025-05-18 15:55:34', '2025-05-18 15:55:34'),
(29, 'เทปูน 1 คิว ใช้ปูนกี่ถุง? คำนวณวัสดุและต้นทุนอย่างมืออาชีพ', 'เรียนรู้วิธีคำนวณปริมาณปูน ทราย หิน สำหรับเทคอนกรีต 1 คิว พร้อมข้อมูลราคาปูนและพื้นที่ที่สามารถเทได้จากปูน 1 ถุง เพื่อวางแผนงานก่อสร้างอย่างมืออาชีพ', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    คู่มือช่างปี 2026: คอนกรีต 1 คิว ใช้ปูนกี่ถุง? สูตรผสมปูน 1:2:4 และเทคนิคการเทพื้นให้แข็งแรงไม่แตกร้าว\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calculator\"></i> อัปเดตข้อมูลทางวิศวกรรมล่าสุด | <i class=\"fa fa-building\"></i> หมวดหมู่: ความรู้งานช่าง, เทคอนกรีต, คำนวณวัสดุ\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #fcf8f2; padding: 25px; border-left: 5px solid #d9534f; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    ไม่ว่าคุณจะเป็นเจ้าของบ้านที่ต้องการปรับปรุงพื้นที่เล็กๆ เอง หรือผู้รับเหมาที่ต้องคุมต้นทุนโครงการใหญ่ คำถามสำคัญที่ต้องตอบให้ได้ก่อนเริ่มงานคือ <strong>\"คอนกรีต 1 คิว ใช้ปูนกี่ถุง?\"</strong> เพราะการกะปริมาณวัสดุที่แม่นยำคือหัวใจของการควบคุมงบประมาณ <br><br>\n                    บทความนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> จะพาคุณไปเจาะลึกสูตรการผสมคอนกรีตมาตรฐาน 240-280 ksc และสัดส่วน 1:2:4 พร้อมเผยเทคนิคการ <a href=\"https://www.theeraphong.com/pour-concrete\" target=\"_blank\" style=\"font-weight: bold; color: #d9534f; text-decoration: underline;\">เทคอนกรีต</a> ให้หน้างานออกมาเรียบเนียน แข็งแรง และไร้รอยแตกร้าวครับ\n                </p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. คอนกรีต 1 คิว (m³) ต้องใช้วัสดุอะไรบ้าง? (สูตรผสมมาตรฐาน 280 ksc)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                คอนกรีต 1 คิว (หรือ 1 ลูกบาศก์เมตร) คือปริมาตรของคอนกรีตในทรงลูกบาศก์กว้าง 1 เมตร x ยาว 1 เมตร x หนา 1 เมตร สำหรับงานโครงสร้างทั่วไป เช่น พื้นบ้าน ลานจอดรถ หรือเสาเข็ม เรามักจะใช้กำลังอัดมาตรฐานที่ 280 ksc (กก./ตร.ซม.) ซึ่งต้องใช้สัดส่วนวัสดุดังนี้:\n            </p>\n            \n            <div class=\"table-responsive\" style=\"margin-top: 20px;\">\n                <table class=\"table table-bordered table-striped\" style=\"font-size: 16px;\">\n                    <thead style=\"background-color: #2c3e50; color: white;\">\n                        <tr>\n                            <th class=\"text-center\">รายการวัสดุ</th>\n                            <th class=\"text-center\">ปริมาณที่ใช้</th>\n                            <th class=\"text-center\">หน่วยนับ</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n                        <tr>\n                            <td><strong>ปูนซีเมนต์ปอร์ตแลนด์ (โครงสร้าง)</strong></td>\n                            <td class=\"text-center\"><strong>6.5</strong></td>\n                            <td class=\"text-center\">ถุง (50 กก./ถุง)</td>\n                        </tr>\n                        <tr>\n                            <td><strong>ทรายหยาบ (ทรายน้ำจืดสะอาด)</strong></td>\n                            <td class=\"text-center\">820</td>\n                            <td class=\"text-center\">กิโลกรัม (ประมาณ 0.5-0.6 คิวทราย)</td>\n                        </tr>\n                        <tr>\n                            <td><strong>หินขนาด 3/4 นิ้ว (20 มม.)</strong></td>\n                            <td class=\"text-center\">1,120</td>\n                            <td class=\"text-center\">กิโลกรัม (ประมาณ 1.0-1.1 คิวหิน)</td>\n                        </tr>\n                        <tr>\n                            <td><strong>น้ำสะอาด (ไม่มีสารปนเปื้อน)</strong></td>\n                            <td class=\"text-center\">130-150</td>\n                            <td class=\"text-center\">ลิตร</td>\n                        </tr>\n                    </tbody>\n                </table>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. สูตรอมตะ 1:2:4 คืออะไร? และทำไมช่างถึงนิยมใช้\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หากคุณไม่มีตู้ชั่งน้ำหนักที่หน้างาน สูตรที่จดจำง่ายที่สุดคือ <strong>สัดส่วนโดยปริมาตร 1:2:4</strong> (ปูน 1 ส่วน : ทราย 2 ส่วน : หิน 4 ส่วน) โดยใช้ \"ถังปูน\" เป็นเกณฑ์วัด ซึ่งสูตรนี้จะให้กำลังอัดคอนกรีตที่เพียงพอสำหรับงานพื้นบ้านทั่วไป \n            </p>\n            <div class=\"panel panel-default\" style=\"border-top: 4px solid #31708f;\">\n                <div class=\"panel-body\">\n                    <p style=\"font-size: 16px; line-height: 1.6;\">\n                        <strong>เคล็ดลับมืออาชีพ:</strong> ปูนซีเมนต์ 1 ถุง (50 กก.) จะมีปริมาตรประมาณ 2 ถังปูน ดังนั้นหากใช้สูตร 1:2:4 ในการผสมปูน 1 ถุง คุณจะต้องใช้: <br>\n                        - ทราย 4 ถังปูน <br>\n                        - หิน 8 ถังปูน <br>\n                        และเติมน้ำให้พอดีสำหรับการทำงาน (ไม่แฉะจนเกินไป)\n                    </p>\n                </div>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. คอนกรีต 1 คิว เทได้กี่ตารางเมตร? (ตารางสรุปตามความหนา)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                การประเมินพื้นที่ช่วยให้เราสั่งคอนกรีตผสมเสร็จหรือเตรียมปูนถุงได้ถูกต้อง พื้นที่ที่คุณจะเทได้จากคอนกรีต 1 คิว มีความสัมพันธ์โดยตรงกับความหนาดังนี้:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-sm-4\">\n                    <div class=\"well text-center\" style=\"border-bottom: 4px solid #5cb85c;\">\n                        <h4>หนา 10 ซม.</h4>\n                        <p style=\"font-size: 28px; font-weight: bold; color: #5cb85c;\">10 ตร.ม.</p>\n                        <p class=\"text-muted\">เหมาะสำหรับพื้นบ้าน, ทางเดิน</p>\n                    </div>\n                </div>\n                <div class=\"col-sm-4\">\n                    <div class=\"well text-center\" style=\"border-bottom: 4px solid #f0ad4e;\">\n                        <h4>หนา 15 ซม.</h4>\n                        <p style=\"font-size: 28px; font-weight: bold; color: #f0ad4e;\">6.67 ตร.ม.</p>\n                        <p class=\"text-muted\">เหมาะสำหรับลานจอดรถยนต์</p>\n                    </div>\n                </div>\n                <div class=\"col-sm-4\">\n                    <div class=\"well text-center\" style=\"border-bottom: 4px solid #d9534f;\">\n                        <h4>หนา 20 ซม.</h4>\n                        <p style=\"font-size: 28px; font-weight: bold; color: #d9534f;\">5 ตร.ม.</p>\n                        <p class=\"text-muted\">เหมาะสำหรับลานจอดรถหนัก</p>\n                    </div>\n                </div>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. เทคนิคการเตรียมหน้างานและการเทคอนกรีตให้ได้คุณภาพ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                การผสมปูนได้สัดส่วนที่ถูกต้องเป็นเพียงครึ่งเดียวของความสำเร็จ อีกครึ่งหนึ่งคือขั้นตอนการทำงานหน้างาน ซึ่งหากทำไม่ถูกวิธี พื้นที่เทปูนอาจเกิดการทรุดตัวหรือแตกร้าวในภายหลังได้ ทีมงาน <a href=\"https://www.theeraphong.com/pour-concrete\" target=\"_blank\" style=\"font-weight: bold; color: #0056b3;\">รับเทปูน</a> ของธีรพงษ์เซอร์วิส ขอแนะนำ 3 หัวใจสำคัญดังนี้:\n            </p>\n            \n            <ul class=\"list-group\" style=\"font-size: 16px;\">\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 style=\"font-weight: bold; color: #333;\"><i class=\"fa fa-truck text-primary\"></i> 1. การบดอัดดินและการปรับระดับ</h4>\n                    <p style=\"line-height: 1.6; margin-top: 10px;\">ก่อนเทคอนกรีต ดินด้านล่างต้องถูกบดอัดให้แน่น และรองพื้นด้วยทรายหยาบพร้อมแผ่นพลาสติกกันความชื้น เพื่อป้องกันไม่ให้ดินดูดน้ำจากคอนกรีตเร็วเกินไปจนทำให้ปูนกรอบ</p>\n                </li>\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 style=\"font-weight: bold; color: #333;\"><i class=\"fa fa-th text-primary\"></i> 2. การวางตะแกรงเหล็ก (Wire Mesh)</h4>\n                    <p style=\"line-height: 1.6; margin-top: 10px;\">ตะแกรงเหล็กต้องถูกยกสูงขึ้นจากพื้นดินประมาณ 3-5 ซม. (ลูกปูนรองเข็ม) เพื่อให้อยู่กึ่งกลางของชั้นคอนกรีต ทำหน้าที่รับแรงดึงและป้องกันรอยร้าวที่เกิดจากการยืดหดตัวของปูน</p>\n                </li>\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 style=\"font-weight: bold; color: #333;\"><i class=\"fa fa-tint text-primary\"></i> 3. การบ่มคอนกรีต (Curing)</h4>\n                    <p style=\"line-height: 1.6; margin-top: 10px;\">หลังจากเทเสร็จและปูนเริ่มเซ็ตตัว ต้องทำการฉีดน้ำเลี้ยงพื้นผิว (Wet Curing) ต่อเนื่องอย่างน้อย 7 วัน เพื่อให้ปูนทำปฏิกิริยาไฮเดรชั่นได้อย่างสมบูรณ์และได้ค่าความแข็งแรงตามสเปก</p>\n                </li>\n            </ul>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> ถาม-ตอบ (FAQ) เรื่องการผสมปูนเทพื้น</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: ใช้ปูนกาว หรือปูนฉาบ เทพื้นได้ไหม?</h4>\n                <p style=\"margin-bottom: 20px;\">A: <strong>ไม่ได้เด็ดขาดครับ</strong> ปูนแต่ละประเภทถูกออกแบบมาให้รับแรงต่างกัน ปูนฉาบเน้นการยึดเกาะผนังแต่รับแรงอัดไม่ได้เหมือนปูนโครงสร้าง พื้นจะแตกร่อนทันทีที่ใช้งานครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: ผสมเอง กับสั่งรถปูน อันไหนคุ้มกว่า?</h4>\n                <p>A: หากใช้ปริมาณมากกว่า 3-5 คิวขึ้นไป <strong>การสั่งรถปูน (Ready-Mixed) จะคุ้มกว่า</strong> ทั้งในแง่ของความเร็ว แรงงาน และความสม่ำเสมอของเนื้อคอนกรีตครับ แต่ถ้าเป็นงานซ่อมแซมเล็กน้อยไม่ถึง 1 คิว การผสมเองด้วยปูนถุงจะคล่องตัวกว่าครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #d9534f; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">วางแผนงานเทปูนอย่างมืออาชีพ ปรึกษาเราฟรี!</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    กะปริมาณไม่ถูก ไม่รู้จะเลือกค่า ksc เท่าไหร่ หรือต้องการทีมงานรับเหมาที่ซื่อสัตย์ ไม่ลดสเปกวัสดุ <br>\n                    <strong>ธีรพงษ์เซอร์วิส</strong> พร้อมให้บริการประเมินราคาและสำรวจหน้างานฟรี ในพื้นที่กรุงเทพฯ และปริมณฑล\n                </p>\n                \n                <a href=\"https://www.theeraphong.com/pour-concrete\" class=\"btn btn-danger btn-lg\" style=\"padding: 15px 40px; font-weight: bold; border-radius: 30px; font-size: 18px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                    <i class=\"fa fa-truck\"></i> ดูบริการเทคอนกรีต และขอใบเสนอราคา\n                </a>\n                \n                <div style=\"margin-top: 20px; font-size: 14px; color: #777;\">\n                    สอบถามเพิ่มเติมโทร: 062-718-8847 | <a href=\"https://line.me/ti/p/h9SHumuTEB\">\n                        <p>ไลน์ไอดี : 0627188847</p>\n                        <img class=\"img-rounded\" width=\"30%\" height=\"auto\"\n                            src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/lineid.webp\" alt=\"lineID\" />\n                    </a>\n\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/services/cd2ec5b2-096b-46cd-bf8b-82a3bf655aed.webp', 27, 'เทปูน-1-คิว-ใช้ปูนกี่ถุง-คำนวณวัสดุและต้นทุนอย่างมืออาชีพ', '2025-05-23 09:15:37', '2025-05-29 14:23:26');
INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(30, 'ถมที่ด้วยเศษวัสดุก่อสร้าง ช่วยประหยัด เสริมพื้นแข็งแรง เหมาะกับงานสร้างกำแพงกันดิน', 'รู้จักการถมที่ด้วยเศษวัสดุก่อสร้าง พร้อมแนวทางเลือกใช้วัสดุให้ปลอดภัย ประหยัด และเตรียมพื้นที่สำหรับงานก่อสร้างกำแพงกันดินอย่างมีประสิทธิภาพ พร้อมบริการจากมืออาชีพ', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    เคล็ดลับงานฐานราก: ถมที่ด้วยเศษวัสดุก่อสร้าง ทางเลือกสุดประหยัด เตรียมพื้นที่ก่อนสร้างกำแพงกันดิน\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-cogs\"></i> หมวดหมู่: การเตรียมหน้างาน, งานฐานราก, วัสดุก่อสร้าง | <i class=\"fa fa-recycle\"></i> Eco-Friendly Construction\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #f8f9fa; padding: 25px; border-left: 5px solid #f0ad4e; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    ในโปรเจกต์งานรับเหมาก่อสร้าง <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\" style=\"color: #0056b3; font-weight: bold;\">กำแพงกันดิน (Retaining Wall)</a> โดยเฉพาะในโครงการขนาดกลางถึงขนาดใหญ่ที่มีสภาพเป็นดินอ่อน ดินเลน หรือมีน้ำขัง หนึ่งในขั้นตอนสำคัญที่หลายคนมักจะมองข้ามคือ <strong>\"การเตรียมพื้นที่หน้างาน (Site Preparation)\"</strong> เพื่อให้เครื่องจักรหนักสามารถเข้าไปทำงานได้อย่างปลอดภัย <br><br>\n                    การถมด้วยดินลูกรังหรือทรายล้วนอาจทำให้งบประมาณบานปลายโดยใช่เหตุ ปัจจุบันวิศวกรและผู้รับเหมาหลายโครงการจึงหันมาเลือกใช้ <strong>“การถมที่ด้วยเศษวัสดุก่อสร้าง (Construction Waste Fill)”</strong> ซึ่งเป็นอีกหนึ่งทางเลือกที่ทั้งคุ้มค่า แข็งแรง และเป็นมิตรกับสิ่งแวดล้อม (Recycle) หากเราเลือกใช้วัสดุและมีกระบวนการบดอัดอย่างถูกวิธีครับ\n                </p>\n            </div>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/0dcca921-8ae9-4259-8708-178f97ecc4e7.webp\" alt=\"ถมที่ด้วยเศษวัสดุก่อสร้าง เตรียมพื้นที่สร้างกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: การนำเศษวัสดุก่อสร้างมาเกลี่ยเพื่อปรับระดับและเพิ่มความแข็งแรงให้พื้นผิวก่อนเริ่มงานฐานราก</em></p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. ทำไมถึงต้องถมพื้นที่หน้างาน ก่อนเริ่มสร้างกำแพงกันดิน?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                การก่อสร้างกำแพงกันดิน จำเป็นต้องใช้เครื่องจักรขนาดใหญ่ เช่น รถแบคโฮ (Excavator) รถปั้นจั่นตอกเสาเข็ม หรือรถกดเสาเข็มไมโครไพล์ หากหน้างานเดิมเป็นดินเหนียวอ่อน หรือพื้นที่ลุ่มต่ำ การนำเครื่องจักรเข้าไปเหยียบโดยตรงอาจทำให้เกิดปัญหา \"รถจมโคลน\" หรือ \"เครื่องจักรพลิกคว่ำ\" ได้ การถมพื้นที่หน้างานจึงมีประโยชน์เชิงวิศวกรรมดังนี้:\n            </p>\n            \n            <ul class=\"list-group\" style=\"font-size: 16px; margin-top: 20px;\">\n                <li class=\"list-group-item\" style=\"padding: 15px;\"><i class=\"fa fa-check-square-o text-success\"></i> <strong>เพิ่มกำลังรับน้ำหนัก (Bearing Capacity):</strong> ทำให้ผิวดินแข็งแรงพอที่จะรองรับน้ำหนักหลายสิบตันของเครื่องจักรหนักได้</li>\n                <li class=\"list-group-item\" style=\"padding: 15px;\"><i class=\"fa fa-check-square-o text-success\"></i> <strong>ปรับระดับพื้นที่ (Leveling):</strong> ช่วยลดความลาดชัน แก้ปัญหาพื้นที่สูง-ต่ำไม่เท่ากัน ทำให้กดเสาเข็มได้ตรง ดิ่งไม่หนีศูนย์</li>\n                <li class=\"list-group-item\" style=\"padding: 15px;\"><i class=\"fa fa-check-square-o text-success\"></i> <strong>ป้องกันปัญหาหน้าฝน:</strong> วัสดุประเภทเศษอิฐเศษปูน จะช่วยแก้ปัญหาน้ำขังและดินโคลนลื่น ทำให้ทีมช่างทำงานได้ต่อเนื่องไม่สะดุด</li>\n            </ul>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/57de4d73-ab3a-4871-9504-4e99b56798f1.webp\" alt=\"เครื่องจักรทำงานบนพื้นที่ถมด้วยเศษปูน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2: พื้นผิวที่ถูกถมและบดอัดด้วยเศษวัสดุก่อสร้าง จะมีความแน่น แข็งแรง รองรับการเคลื่อนที่ของเครื่องจักรได้ดีเยี่ยม</em></p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. \"เศษวัสดุก่อสร้าง\" หรือ \"เศษวัสดุเหลือใช้\" มีอะไรบ้าง?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลายคนมักมีคำถามว่า <em>เศษวัสดุเหลือใช้มีอะไรบ้าง?</em> หรือ <em>เศษวัสดุมีอะไรบ้างที่นำมาถมที่ได้?</em> ในทางวิศวกรรมก่อสร้าง เราจะแบ่ง <strong>เศษวัสดุก่อสร้าง (Construction and Demolition Waste - C&D)</strong> ออกเป็นประเภทที่ \"นำมาถมได้\" และ \"ห้ามนำมาถม\" ดังนี้ครับ:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 20px;\">\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-success\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold;\"><i class=\"fa fa-thumbs-up\"></i> วัสดุที่เหมาะสำหรับนำมาถมที่</h4></div>\n                        <div class=\"panel-body\">\n                            <ul style=\"line-height: 1.8;\">\n                                <li><strong>เศษปูน / คอนกรีตเก่า:</strong> เศษเสาเข็มหัก พื้นคอนกรีตทุบ (แข็งแรงที่สุด)</li>\n                                <li><strong>อิฐหัก / อิฐมอญ / อิฐบล็อก:</strong> ระบายน้ำได้ดีเยี่ยม</li>\n                                <li><strong>กระเบื้องดินเผา หรือกระเบื้องหลังคาแตก</strong></li>\n                                <li><strong>เศษวัสดุธรรมชาติ:</strong> เช่น เศษหิน กรวด ดินทรายที่ปนมากับไซต์งาน</li>\n                            </ul>\n                        </div>\n                    </div>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-danger\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold;\"><i class=\"fa fa-ban\"></i> วัสดุที่ \"ห้าม\" นำมาถมที่เด็ดขาด</h4></div>\n                        <div class=\"panel-body\">\n                            <ul style=\"line-height: 1.8;\">\n                                <li><strong>เศษไม้ธรรมชาติ / เศษไม้แบบหล่อ:</strong> เพราะจะผุพังตามกาลเวลาและทำให้ดินทรุดเป็นโพรง รวมถึงเป็นแหล่งเพาะพันธุ์ปลวก</li>\n                                <li><strong>ขยะพลาสติก / โฟม / ถุงปูน:</strong> ไม่ย่อยสลาย และทำให้ชั้นดินไม่แน่น</li>\n                                <li><strong>เศษเหล็กยาว / เหล็กเส้น:</strong> อาจแทงทะลุล้อเครื่องจักร หรือเป็นอันตรายต่อทีมช่าง</li>\n                            </ul>\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/1b07cce0-4bea-4127-b399-6bd8d9fbd6c9.webp\" alt=\"เศษวัสดุก่อสร้าง เศษปูน อิฐหัก สำหรับถมที่\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 3: ลักษณะของเศษอิฐ เศษปูน และคอนกรีตหัก ที่ผ่านการคัดแยกขยะอันตรายออกแล้ว เหมาะแก่การทำชั้นฐานรากชั่วคราว</em></p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ไขข้อข้องใจ: \"เศษปูน\" ถมที่ได้ไหม? และเอาไปทำอะไรได้บ้าง?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                สำหรับคำถามยอดฮิตที่ว่า <em>เศษปูนทำอะไรได้บ้าง?</em> หรือ <em>เศษปูนถมที่ได้หรือไม่?</em> คำตอบแบบฟันธงคือ <strong>\"ได้แน่นอนครับ และดีมากๆ ด้วย\"</strong> \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เศษปูนที่ได้จากการทุบตึก หรือเศษคอนกรีตเหลือทิ้ง เมื่อนำมาถมที่จะทำหน้าที่เสมือน \"หินคลุก\" ขนาดใหญ่ โครงสร้างของคอนกรีตจะรับแรงกดทับได้มหาศาล (High Compressive Strength) แต่การนำเศษปูนมาถมที่ให้ได้มาตรฐาน จะต้องมีเทคนิคเล็กน้อยครับ:\n            </p>\n            \n            <div class=\"well\" style=\"background-color: #fdf7f7; border-color: #ebccd1;\">\n                <h4 style=\"color: #c9302c; font-weight: bold; margin-top: 0;\">💡 เทคนิคการถมที่ด้วยเศษปูน (Concrete Rubble Filling)</h4>\n                <ol style=\"line-height: 1.8; margin-bottom: 0;\">\n                    <li><strong>ต้องไม่มีสารเคมีปนเปื้อน:</strong> เพื่อไม่ให้เกิดผลกระทบต่อน้ำใต้ดิน</li>\n                    <li><strong>แยกเศษกระเบื้องแหลมคม:</strong> หากเป็นเศษปูนที่ติดกระเบื้อง ควรนำรถแบคโฮมาบดทับให้แตกละเอียดก่อน เพื่อป้องกันอันตราย</li>\n                    <li><strong>ต้องใช้ \"ดินหรือทราย\" กลบช่องว่าง:</strong> เศษปูนก้อนใหญ่มักจะมีช่องโหว่ (Voids) ระหว่างก้อน การถมที่ดีคือการเทเศษปูนลงไปก่อน แล้วนำทรายขี้เป็ดหรือดินมาเกลี่ยทับให้ไหลลงไปอุดช่องว่าง จากนั้นใช้รถบดอัดให้แน่น ผิวหน้างานจะเรียบและแข็งแกร่งสุดๆ ครับ</li>\n                </ol>\n            </div>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/72dcb8ff-71b2-414a-a564-7650a3e44778.webp\" alt=\"ข้อดีของการใช้เศษปูนถมที่\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 4: การนำเศษปูนมาใช้ถมที่ ไม่เพียงแต่แข็งแรง แต่ยังเป็นการนำวัสดุกลับมาใช้ใหม่ (Recycle) ช่วยลดภาวะโลกร้อน</em></p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. อัปเดตราคา: ถมที่ด้วยเศษวัสดุก่อสร้าง และเศษปูน ราคาเท่าไหร่?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เหตุผลหลักที่โครงการก่อสร้างนิยมใช้เศษวัสดุ คือ <strong>\"ความประหยัด (Cost-Effective)\"</strong> เมื่อเทียบกับการซื้อดินถมทั่วไป (ดินดำ, ดินลูกรัง) การถมที่ด้วยเศษปูนจะมีราคาที่ถูกกว่ามาก ลองมาดูตารางเปรียบเทียบ <em>เศษปูนราคา</em> และ <em>เศษปูนถมที่ราคา</em> เบื้องต้นกันครับ:\n            </p>\n\n            <div class=\"table-responsive\" style=\"margin-top: 20px;\">\n                <table class=\"table table-bordered table-striped table-hover\" style=\"font-size: 16px;\">\n                    <thead style=\"background-color: #2c3e50; color: white;\">\n                        <tr>\n                            <th class=\"text-center\" style=\"width: 50%;\">ประเภทวัสดุถมที่</th>\n                            <th class=\"text-center\" style=\"width: 50%;\">ราคาประเมินโดยประมาณ (บาท / คิว)*</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n                        <tr>\n                            <td><strong>เศษปูนก้อนใหญ่ / คอนกรีตเก่าทุบ</strong></td>\n                            <td class=\"text-center text-primary\" style=\"font-weight: bold;\">100 – 200 บาท</td>\n                        </tr>\n                        <tr>\n                            <td><strong>อิฐหัก / เศษกระเบื้องบดละเอียด</strong></td>\n                            <td class=\"text-center text-primary\" style=\"font-weight: bold;\">80 – 150 บาท</td>\n                        </tr>\n                        <tr>\n                            <td><strong>เศษวัสดุผสม (ปนดิน / หิน / ทราย)</strong></td>\n                            <td class=\"text-center text-primary\" style=\"font-weight: bold;\">50 – 120 บาท</td>\n                        </tr>\n                        <tr style=\"background-color: #f2dede;\">\n                            <td><em>(เปรียบเทียบ) ดินลูกรัง / ทรายถม</em></td>\n                            <td class=\"text-center text-danger\" style=\"font-weight: bold;\">250 – 400+ บาท</td>\n                        </tr>\n                    </tbody>\n                </table>\n            </div>\n            <p class=\"text-muted\" style=\"font-size: 14px;\"><em>*หมายเหตุ: ราคาดังกล่าวเป็นเพียงราคาประเมินเฉพาะค่าวัสดุ อาจมีการเปลี่ยนแปลงขึ้นอยู่กับ \"ระยะทางในการขนส่ง\", \"ปริมาณที่สั่ง\", และ \"ค่าแรงเครื่องจักรในการเกลี่ยบดอัด\"</em></p>\n\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                5. ปัญหาโลกแตก: เศษวัสดุก่อสร้าง และ เศษปูน ทิ้งที่ไหน?\n            </h2>\n            \n            <div class=\"row\">\n                <div class=\"col-md-7\">\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        หากไซต์งานของคุณมีเศษปูนเหลือใช้ แต่ไม่ได้มีความจำเป็นต้องใช้ถมที่ หลายคนมักจะปวดหัวว่า <em>เศษปูนทิ้งที่ไหน?</em> หรือ <em>เศษวัสดุก่อสร้างทิ้งที่ไหนได้บ้างโดยไม่ผิดกฎหมาย?</em> \n                    </p>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        การแอบนำเศษวัสดุก่อสร้างไปทิ้งตามที่สาธารณะหรือข้างทาง ถือเป็นความผิดตาม พ.ร.บ. รักษาความสะอาดฯ มีโทษปรับที่รุนแรงครับ วิธีการจัดการที่ถูกต้องและยั่งยืนคือ:\n                    </p>\n                    <ul style=\"line-height: 1.8; font-size: 16px;\">\n                        <li>ติดต่อ <strong>ศูนย์กำจัดขยะก่อสร้าง (C&D Waste Management)</strong> ของเอกชนที่มีใบอนุญาตถูกต้อง</li>\n                        <li>ส่งเข้า <strong>โรงงานรีไซเคิลคอนกรีต</strong> เพื่อบดย่อยนำกลับมาใช้เป็นมวลรวม (Aggregate)</li>\n                        <li><strong>ประกาศแจกฟรี / ขายถูก:</strong> ให้กับผู้รับเหมาหรือเจ้าของที่ดินที่กำลังมองหาวัสดุไปถมที่ลุ่มต่ำ (Win-Win Situation)</li>\n                    </ul>\n                </div>\n                <div class=\"col-md-5 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/2d1b89ab-fa0a-4c2a-a9e2-b2fd383da8c9.webp\" alt=\"เศษวัสดุก่อสร้างทิ้งที่ไหน การจัดการขยะก่อสร้าง\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>การจัดการเศษวัสดุก่อสร้างอย่างถูกวิธี ช่วยรักษาสิ่งแวดล้อมและไม่ผิดกฎหมาย</em></p>\n                </div>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                6. ตัวอย่างผลงานจริง: ถมพื้นที่ด้วยเศษปูน เพื่อสร้างกำแพงกันดิน @นนทบุรี\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เพื่อเห็นภาพที่ชัดเจนขึ้น ทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> ขอหยิบยกเคสตัวอย่างหน้างานที่จังหวัดนนทบุรี เราได้รับโจทย์ให้สร้างกำแพงกันดินริมคลอง แต่สภาพพื้นที่เป็นดินเลนอ่อนยวบยาบ ไม่สามารถนำรถกดเสาเข็มไมโครไพล์เข้าพื้นที่ได้ \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ทางทีมวิศวกรจึงตัดสินใจใช้เทคนิค <strong>\"การถมด้วยเศษปูนบดละเอียด ร่วมกับเศษอิฐ-หิน\"</strong> บนพื้นที่กว่า 500 ตารางเมตร โดยนำรถแบคโฮมาทำการเกลี่ยและใช้กระบวยรถกดทับ (Compaction) ให้แน่น ควบคุมระดับดินตามมาตรฐานงานฐานราก\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/966a0419-99ac-4e8c-b6f9-d9bfaa8af967.webp\" alt=\"ผลงานถมพื้นที่หน้างานสร้างกำแพงกันดิน นนทบุรี\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 6: ผลลัพธ์หน้างานจริง พื้นที่แน่น แข็งแรง เครื่องจักรเจาะเสาเข็มสามารถเข้าทำงานต่อได้ทันทีในวันรุ่งขึ้น โดยไม่มีปัญหาการทรุดตัวเลยแม้แต่น้อย</em></p>\n            </div>\n\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> คำถามที่พบบ่อย (FAQ) เกี่ยวกับการถมดินด้วยเศษวัสดุ</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: ถมที่ด้วยเศษปูนแล้ว อนาคตสามารถปลูกต้นไม้ได้ไหม?</h4>\n                <p style=\"margin-bottom: 20px;\">A: เศษปูนและเศษคอนกรีตมีความเป็นด่างสูงและไม่มีแร่ธาตุอาหาร หากถมจนถึงผิวดินชั้นบนสุดจะไม่เหมาะกับการปลูกต้นไม้ครับ หากวางแผนจะจัดสวน แนะนำให้ถมเศษปูนไว้ที่ชั้นล่าง (ทำเป็น Sub-base) แล้วนำ \"ดินหน้า (Topsoil)\" มาถมทับด้านบนสุดในความหนาอย่างน้อย 50-80 ซม. เพื่อให้รากต้นไม้เดินได้ครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: จำเป็นต้องใช้รถบดอัด (Road Roller) หรือไม่?</h4>\n                <p>A: หากเป็นการถมเพื่อทำถนนหรือลานจอดรถถาวร จำเป็นต้องใช้รถบดสั่นสะเทือนเพื่อลดโพรงอากาศครับ แต่หากเป็นการถมชั่วคราวเพื่อให้เครื่องจักรเข้าไปทำกำแพงกันดิน การใช้แบคโฮเกลี่ยและตบให้แน่น (Track rolling) ก็ถือว่าเพียงพอแล้วครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #d9534f; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">ทำไมต้องเลือก ธีรพงษ์เซอร์วิส?</h3>\n                <p style=\"font-size: 16px; margin-bottom: 20px; color: #555;\">\n                    <i class=\"fa fa-check text-success\"></i> ประสบการณ์ด้านงานถมที่และฐานรากกว่า 20 ปี <br>\n                    <i class=\"fa fa-check text-success\"></i> มีเครื่องจักรหนักเฉพาะทางครบวงจร (แบคโฮ, รถหกล้อ, เครื่องกดเข็ม) <br>\n                    <i class=\"fa fa-check text-success\"></i> ทีมงานเข้าใจหน้างานก่อสร้างจริง แก้ปัญหาหน้างานได้ตรงจุด <br>\n                    <i class=\"fa fa-check text-success\"></i> พร้อมลงพื้นที่ประเมินและให้คำปรึกษาฟรี!\n                </p>\n                \n                <div style=\"font-size: 24px; color: #c9302c; font-weight: bold; margin-top: 25px; margin-bottom: 20px;\">\n                    <i class=\"fa fa-phone\"></i> สนใจใช้บริการ หรือปรึกษางาน โทร: 062-718-8847, 087-700-7463\n                </div>\n\n                <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-danger btn-lg\" style=\"padding: 15px 40px; font-weight: bold; border-radius: 30px; font-size: 18px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                    <i class=\"fa fa-shield\"></i> ดูบริการรับทำกำแพงกันดินของเรา\n                </a>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/services/0dcca921-8ae9-4259-8708-178f97ecc4e7.webp', 10, 'ถมที่ด้วยเศษวัสดุก่อสร้าง-ช่วยประหยัด-เสริมพื้นแข็งแรง-เหมาะกับงานสร้างกำแพงกันดิน', '2025-05-29 15:12:08', '2025-05-29 15:29:00'),
